/// The enumerated values to specify how the compounding calculation is done
enum class CompoundingTypeEnum {
    /// Compounding is not applicable
    NONE,
    /// Compounding is done only on business days, i.e. not compounded each day on weekends or holidays.
    BUSINESS,
    /// Compounding is done on each calendar day.
    CALENDAR
};

/// Convert CompoundingTypeEnum to its string representation.
inline const char* to_string(CompoundingTypeEnum value) {
    switch (value) {
        case CompoundingTypeEnum::NONE: return "None";
        case CompoundingTypeEnum::BUSINESS: return "Business";
        case CompoundingTypeEnum::CALENDAR: return "Calendar";
    }
    return "unknown";
}

/// Parse a string into CompoundingTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CompoundingTypeEnum& out) {
    if (std::strcmp(str, "None") == 0) { out = CompoundingTypeEnum::NONE; return true; }
    if (std::strcmp(str, "Business") == 0) { out = CompoundingTypeEnum::BUSINESS; return true; }
    if (std::strcmp(str, "Calendar") == 0) { out = CompoundingTypeEnum::CALENDAR; return true; }
    return false;
}

/// How often is rounding performed
enum class RoundingFrequencyEnum {
    /// Rounding is done on each day
    DAILY,
    /// Rounding is done only at the end of the period
    PERIOD_END
};

/// Convert RoundingFrequencyEnum to its string representation.
inline const char* to_string(RoundingFrequencyEnum value) {
    switch (value) {
        case RoundingFrequencyEnum::DAILY: return "Daily";
        case RoundingFrequencyEnum::PERIOD_END: return "PeriodEnd";
    }
    return "unknown";
}

/// Parse a string into RoundingFrequencyEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, RoundingFrequencyEnum& out) {
    if (std::strcmp(str, "Daily") == 0) { out = RoundingFrequencyEnum::DAILY; return true; }
    if (std::strcmp(str, "PeriodEnd") == 0) { out = RoundingFrequencyEnum::PERIOD_END; return true; }
    return false;
}

/// The enumerated values to specify the day count fraction.
enum class DayCountFractionEnum {
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (v), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (e) or Annex to the 2000 ISDA Definitions (June 2000 Version), Section 4.16. Day Count Fraction, paragraph (d).
    ACT_360,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (ix), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (i).
    ACT_365_L,
    /// Per CFTC definitions.
    ACT_364,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (iv), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (d) or Annex to the 2000 ISDA Definitions (June 2000 Version), Section 4.16. Day Count Fraction, paragraph (c).
    ACT_365_FIXED,
    /// The Fixed/Floating Amount will be calculated in accordance with the 'BASE EXACT/EXACT' day count fraction, as defined in the 'Definitions Communes plusieurs Additifs Techniques' published by the Association Francaise des Banques in September 1994.
    ACT_ACT_AFB,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (iii), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (c). This day count fraction code is applicable for transactions booked under the 2021 ISDA Definitions and the 2006 ISDA Definitions. Transactions under the 2000 ISDA Definitions should use the ACT/ACT.ISMA code instead.
    ACT_ACT_ICMA,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (ii), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (b) or Annex to the 2000 ISDA Definitions (June 2000 Version), Section 4.16. Day Count Fraction, paragraph (b). Note that going from FpML 2.0 Recommendation to the FpML 3.0 Trial Recommendation the code in FpML 2.0 'ACT/365.ISDA' became 'ACT/ACT.ISDA'.
    ACT_ACT_ISDA,
    /// The Fixed/Floating Amount will be calculated in accordance with Rule 251 of the statutes, by-laws, rules and recommendations of the International Securities Market Association, as published in April 1999, as applied to straight and convertible bonds issued after December 31, 1998, as though the Fixed/Floating Amount were the interest coupon on such a bond. This day count fraction code is applicable for transactions booked under the 2000 ISDA Definitions. Transactions under the 2021 ISDA Definitions and the 2006 ISDA Definitions should use the ACT/ACT.ICMA code instead.
    ACT_ACT_ISMA,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (x). Supercedes BUS/252, the number of Business Days in the Calculation Period or Compounding Period in respect of which payment is being made divided by 252.
    CAL_252,
    /// Per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (a) or Annex to the 2000 ISDA Definitions (June 2000 Version), Section 4.16. Day Count Fraction, paragraph (a).
    _1_1,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (vii), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (g) or Annex to the 2000 ISDA Definitions (June 2000 Version), Section 4.16. Day Count Fraction, paragraph (f). Note that the algorithm defined for this day count fraction has changed between the 2000 ISDA Definitions and 2006 ISDA Definitions. See Introduction to the 2006 ISDA Definitions for further information relating to this change.
    _30_E_360,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (viii), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (h). Note the algorithm for this day count fraction under the 2006 ISDA Definitions is designed to yield the same results in practice as the version of the 30E/360 day count fraction defined in the 2000 ISDA Definitions. See Introduction to the 2006 ISDA Definitions for further information relating to this change.
    _30_E_360_ISDA,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (vi), per 2006 ISDA Definitions, Section 4.16. Day Count Fraction, paragraph (f) or Annex to the 2000 ISDA Definitions (June 2000 Version), Section 4.16. Day Count Fraction, paragraph (e).
    _30_360,
    /// Per 2021 ISDA Definitions, Section 4.6.1 Day Count Fraction, paragraph (xi), the calculation mechanics are driven deterministically by the Calculation Period Frequency (i.e. 0.25 if it is three months, 0.5 if it is 6 months, 1 if it is a year), except that if the first Calculation Period or the final Calculation Period is less than the Calculation Period Frequency, Actual/Actual (ISDA) shall apply to that Calculation Period
    RBA_BOND_BASIS
};

/// Convert DayCountFractionEnum to its string representation.
inline const char* to_string(DayCountFractionEnum value) {
    switch (value) {
        case DayCountFractionEnum::ACT_360: return "ACT_360";
        case DayCountFractionEnum::ACT_365_L: return "ACT_365L";
        case DayCountFractionEnum::ACT_364: return "ACT_364";
        case DayCountFractionEnum::ACT_365_FIXED: return "ACT_365_FIXED";
        case DayCountFractionEnum::ACT_ACT_AFB: return "ACT_ACT_AFB";
        case DayCountFractionEnum::ACT_ACT_ICMA: return "ACT_ACT_ICMA";
        case DayCountFractionEnum::ACT_ACT_ISDA: return "ACT_ACT_ISDA";
        case DayCountFractionEnum::ACT_ACT_ISMA: return "ACT_ACT_ISMA";
        case DayCountFractionEnum::CAL_252: return "CAL_252";
        case DayCountFractionEnum::_1_1: return "_1_1";
        case DayCountFractionEnum::_30_E_360: return "_30E_360";
        case DayCountFractionEnum::_30_E_360_ISDA: return "_30E_360_ISDA";
        case DayCountFractionEnum::_30_360: return "_30_360";
        case DayCountFractionEnum::RBA_BOND_BASIS: return "RBA_BOND_BASIS";
    }
    return "unknown";
}

/// Parse a string into DayCountFractionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, DayCountFractionEnum& out) {
    if (std::strcmp(str, "ACT_360") == 0) { out = DayCountFractionEnum::ACT_360; return true; }
    if (std::strcmp(str, "ACT_365L") == 0) { out = DayCountFractionEnum::ACT_365_L; return true; }
    if (std::strcmp(str, "ACT_364") == 0) { out = DayCountFractionEnum::ACT_364; return true; }
    if (std::strcmp(str, "ACT_365_FIXED") == 0) { out = DayCountFractionEnum::ACT_365_FIXED; return true; }
    if (std::strcmp(str, "ACT_ACT_AFB") == 0) { out = DayCountFractionEnum::ACT_ACT_AFB; return true; }
    if (std::strcmp(str, "ACT_ACT_ICMA") == 0) { out = DayCountFractionEnum::ACT_ACT_ICMA; return true; }
    if (std::strcmp(str, "ACT_ACT_ISDA") == 0) { out = DayCountFractionEnum::ACT_ACT_ISDA; return true; }
    if (std::strcmp(str, "ACT_ACT_ISMA") == 0) { out = DayCountFractionEnum::ACT_ACT_ISMA; return true; }
    if (std::strcmp(str, "CAL_252") == 0) { out = DayCountFractionEnum::CAL_252; return true; }
    if (std::strcmp(str, "_1_1") == 0) { out = DayCountFractionEnum::_1_1; return true; }
    if (std::strcmp(str, "_30E_360") == 0) { out = DayCountFractionEnum::_30_E_360; return true; }
    if (std::strcmp(str, "_30E_360_ISDA") == 0) { out = DayCountFractionEnum::_30_E_360_ISDA; return true; }
    if (std::strcmp(str, "_30_360") == 0) { out = DayCountFractionEnum::_30_360; return true; }
    if (std::strcmp(str, "RBA_BOND_BASIS") == 0) { out = DayCountFractionEnum::RBA_BOND_BASIS; return true; }
    return false;
}

/// The enumerated values to specify the method of calculation to be used when averaging rates. Per ISDA 2000 Definitions, Section 6.2. Certain Definitions Relating to Floating Amounts.
enum class AveragingWeightingMethodEnum {
    /// The arithmetic mean of the relevant rates for each reset date.
    UNWEIGHTED,
    /// The arithmetic mean of the relevant rates in effect for each day in a calculation period calculated by multiplying each relevant rate by the number of days such relevant rate is in effect, determining the sum of such products and dividing such sum by the number of days in the calculation period.
    WEIGHTED
};

/// Convert AveragingWeightingMethodEnum to its string representation.
inline const char* to_string(AveragingWeightingMethodEnum value) {
    switch (value) {
        case AveragingWeightingMethodEnum::UNWEIGHTED: return "Unweighted";
        case AveragingWeightingMethodEnum::WEIGHTED: return "Weighted";
    }
    return "unknown";
}

/// Parse a string into AveragingWeightingMethodEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AveragingWeightingMethodEnum& out) {
    if (std::strcmp(str, "Unweighted") == 0) { out = AveragingWeightingMethodEnum::UNWEIGHTED; return true; }
    if (std::strcmp(str, "Weighted") == 0) { out = AveragingWeightingMethodEnum::WEIGHTED; return true; }
    return false;
}

/// Specifies enumerations for the type of averaging calculation.
enum class AveragingCalculationMethodEnum {
    /// Refers to the calculation of an average by taking the sum of observations divided by the count of observations.
    ARITHMETIC,
    /// Refers to the calculation of an average by taking the nth root of the product of n observations.
    GEOMETRIC,
    /// Refers to the calculation of an average by taking the reciprocal of the arithmetic mean of the reciprocals of the observations.
    HARMONIC
};

/// Convert AveragingCalculationMethodEnum to its string representation.
inline const char* to_string(AveragingCalculationMethodEnum value) {
    switch (value) {
        case AveragingCalculationMethodEnum::ARITHMETIC: return "Arithmetic";
        case AveragingCalculationMethodEnum::GEOMETRIC: return "Geometric";
        case AveragingCalculationMethodEnum::HARMONIC: return "Harmonic";
    }
    return "unknown";
}

/// Parse a string into AveragingCalculationMethodEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AveragingCalculationMethodEnum& out) {
    if (std::strcmp(str, "Arithmetic") == 0) { out = AveragingCalculationMethodEnum::ARITHMETIC; return true; }
    if (std::strcmp(str, "Geometric") == 0) { out = AveragingCalculationMethodEnum::GEOMETRIC; return true; }
    if (std::strcmp(str, "Harmonic") == 0) { out = AveragingCalculationMethodEnum::HARMONIC; return true; }
    return false;
}

/// The enumerated values to specify the rounding direction and precision to be used in the rounding of a number.  Used by function cdm.base.math.RoundToPrecision.
enum class RoundingDirectionEnum {
    /// A fractional number will be rounded up to the specified number of decimal places (the precision). For example, 5.21 and 5.25 rounded up to 1 decimal place are 5.3 and 5.3 respectively.
    UP,
    /// A fractional number will be rounded down to the specified number of decimal places (the precision). For example, 5.29 and 5.25 rounded down to 1 decimal place are 5.2 and 5.2 respectively.
    DOWN,
    /// A fractional number will be rounded either up or down to the specified number of decimal places (the precision) depending on its value. For example, 5.24 would be rounded down to 5.2 and 5.25 would be rounded up to 5.3 if a precision of 1 decimal place were specified.
    NEAREST
};

/// Convert RoundingDirectionEnum to its string representation.
inline const char* to_string(RoundingDirectionEnum value) {
    switch (value) {
        case RoundingDirectionEnum::UP: return "Up";
        case RoundingDirectionEnum::DOWN: return "Down";
        case RoundingDirectionEnum::NEAREST: return "Nearest";
    }
    return "unknown";
}

/// Parse a string into RoundingDirectionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, RoundingDirectionEnum& out) {
    if (std::strcmp(str, "Up") == 0) { out = RoundingDirectionEnum::UP; return true; }
    if (std::strcmp(str, "Down") == 0) { out = RoundingDirectionEnum::DOWN; return true; }
    if (std::strcmp(str, "Nearest") == 0) { out = RoundingDirectionEnum::NEAREST; return true; }
    return false;
}

/// The enumerated values to specify the rounding direction when rounding of a number to nearest.  Used by function cdm.base.math.RoundToNearest.
enum class RoundingModeEnum {
    /// A number will be rounded down to the specified nearest number. For example, 529 rounded down to the nearest 10 is 520.
    DOWN,
    /// A number will be rounded up to the specified nearest number. For example, 521 rounded up to the nearest 10 is 530.
    UP
};

/// Convert RoundingModeEnum to its string representation.
inline const char* to_string(RoundingModeEnum value) {
    switch (value) {
        case RoundingModeEnum::DOWN: return "Down";
        case RoundingModeEnum::UP: return "Up";
    }
    return "unknown";
}

/// Parse a string into RoundingModeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, RoundingModeEnum& out) {
    if (std::strcmp(str, "Down") == 0) { out = RoundingModeEnum::DOWN; return true; }
    if (std::strcmp(str, "Up") == 0) { out = RoundingModeEnum::UP; return true; }
    return false;
}

/// Represents the enumerated values to specify a logical quantification, i.e. either All or Any.
enum class QuantifierEnum {
    /// Specifies that the condition in the scope of the quantifier is true of every member of the domain i.e. every one of the elements in scope.
    ALL,
    /// Specifies that the condition in the scope of the quantifier is true of at least one member of the domain i.e. one or more of the elements in scope.
    ANY
};

/// Convert QuantifierEnum to its string representation.
inline const char* to_string(QuantifierEnum value) {
    switch (value) {
        case QuantifierEnum::ALL: return "All";
        case QuantifierEnum::ANY: return "Any";
    }
    return "unknown";
}

/// Parse a string into QuantifierEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, QuantifierEnum& out) {
    if (std::strcmp(str, "All") == 0) { out = QuantifierEnum::ALL; return true; }
    if (std::strcmp(str, "Any") == 0) { out = QuantifierEnum::ANY; return true; }
    return false;
}

enum class CompareOp {
    GREATER_THAN,
    GREATER_THAN_OR_EQUALS,
    EQUALS,
    LESS_THAN_OR_EQUALS,
    LESS_THAN
};

/// Convert CompareOp to its string representation.
inline const char* to_string(CompareOp value) {
    switch (value) {
        case CompareOp::GREATER_THAN: return "GreaterThan";
        case CompareOp::GREATER_THAN_OR_EQUALS: return "GreaterThanOrEquals";
        case CompareOp::EQUALS: return "Equals";
        case CompareOp::LESS_THAN_OR_EQUALS: return "LessThanOrEquals";
        case CompareOp::LESS_THAN: return "LessThan";
    }
    return "unknown";
}

/// Parse a string into CompareOp. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CompareOp& out) {
    if (std::strcmp(str, "GreaterThan") == 0) { out = CompareOp::GREATER_THAN; return true; }
    if (std::strcmp(str, "GreaterThanOrEquals") == 0) { out = CompareOp::GREATER_THAN_OR_EQUALS; return true; }
    if (std::strcmp(str, "Equals") == 0) { out = CompareOp::EQUALS; return true; }
    if (std::strcmp(str, "LessThanOrEquals") == 0) { out = CompareOp::LESS_THAN_OR_EQUALS; return true; }
    if (std::strcmp(str, "LessThan") == 0) { out = CompareOp::LESS_THAN; return true; }
    return false;
}

