/// Union of the enumerated values defined by the International Standards Organization (ISO) and the FpML nonISOCurrencyScheme which consists of offshore and historical currencies (https://www.fpml.org/coding-scheme/non-iso-currency), as of 28-Oct-2016.
enum class CurrencyCodeEnum {
    /// Offshore Chinese Yuan traded in Hong Kong.
    CNH,
    /// Offshore Chinese Yuan traded in Taiwan.
    CNT,
    /// Guernsey Pound.
    GGP,
    /// Isle of Man Pound.
    IMP,
    /// Jersey Pound.
    JEP,
    /// Tuvaluan Dollar.
    KID,
    /// Monegasque Franc.
    MCF,
    /// Sammarinese Lira.
    SML,
    /// Vatican Lira.
    VAL
};

/// Convert CurrencyCodeEnum to its string representation.
inline const char* to_string(CurrencyCodeEnum value) {
    switch (value) {
        case CurrencyCodeEnum::CNH: return "CNH";
        case CurrencyCodeEnum::CNT: return "CNT";
        case CurrencyCodeEnum::GGP: return "GGP";
        case CurrencyCodeEnum::IMP: return "IMP";
        case CurrencyCodeEnum::JEP: return "JEP";
        case CurrencyCodeEnum::KID: return "KID";
        case CurrencyCodeEnum::MCF: return "MCF";
        case CurrencyCodeEnum::SML: return "SML";
        case CurrencyCodeEnum::VAL: return "VAL";
    }
    return "unknown";
}

/// Parse a string into CurrencyCodeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CurrencyCodeEnum& out) {
    if (std::strcmp(str, "CNH") == 0) { out = CurrencyCodeEnum::CNH; return true; }
    if (std::strcmp(str, "CNT") == 0) { out = CurrencyCodeEnum::CNT; return true; }
    if (std::strcmp(str, "GGP") == 0) { out = CurrencyCodeEnum::GGP; return true; }
    if (std::strcmp(str, "IMP") == 0) { out = CurrencyCodeEnum::IMP; return true; }
    if (std::strcmp(str, "JEP") == 0) { out = CurrencyCodeEnum::JEP; return true; }
    if (std::strcmp(str, "KID") == 0) { out = CurrencyCodeEnum::KID; return true; }
    if (std::strcmp(str, "MCF") == 0) { out = CurrencyCodeEnum::MCF; return true; }
    if (std::strcmp(str, "SML") == 0) { out = CurrencyCodeEnum::SML; return true; }
    if (std::strcmp(str, "VAL") == 0) { out = CurrencyCodeEnum::VAL; return true; }
    return false;
}

/// Represents an enumeration list to identify the type of entity issuing or guaranteeing the collateral asset.
enum class CollateralEntityTypeEnum {
    /// Specifies international organisations and multilateral banks, entities constituted by treaties or with multiple sovereign members includes Multilateral development Banks.
    SUPRA_NATIONAL,
    /// Specifies Sovereign, Government Debt Securities including Central Banks.
    SOVEREIGN_CENTRAL_BANK,
    /// Specifies institutions or bodies, typically constituted by statute, with a function mandated by the government and subject to government supervision inclusive of profit- and non-profit making bodies. Includes the US Agencies and GSEs and the EU concept of public sector entities. Excluding any entities which are also Regional Government.
    QUASI_GOVERNMENT,
    /// Specifies Regional Governments including states within countries, local authorities and municipalities.
    REGIONAL_GOVERNMENT,
    /// Specifies corporate bodies including Banks.
    CORPORATE,
    /// Specifies a vehicle (with or without separate legal personality) designed for the purposes of collective investment towards a defined investment goal.
    FUND,
    /// Specifies a vehicle setup for the purpose of acquisition and financing of specific assets on a limited recourse basis. E.g. asset backed securities, including securitisations.
    SPECIAL_PURPOSE_VEHICLE
};

/// Convert CollateralEntityTypeEnum to its string representation.
inline const char* to_string(CollateralEntityTypeEnum value) {
    switch (value) {
        case CollateralEntityTypeEnum::SUPRA_NATIONAL: return "SupraNational";
        case CollateralEntityTypeEnum::SOVEREIGN_CENTRAL_BANK: return "SovereignCentralBank";
        case CollateralEntityTypeEnum::QUASI_GOVERNMENT: return "QuasiGovernment";
        case CollateralEntityTypeEnum::REGIONAL_GOVERNMENT: return "RegionalGovernment";
        case CollateralEntityTypeEnum::CORPORATE: return "Corporate";
        case CollateralEntityTypeEnum::FUND: return "Fund";
        case CollateralEntityTypeEnum::SPECIAL_PURPOSE_VEHICLE: return "SpecialPurposeVehicle";
    }
    return "unknown";
}

/// Parse a string into CollateralEntityTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CollateralEntityTypeEnum& out) {
    if (std::strcmp(str, "SupraNational") == 0) { out = CollateralEntityTypeEnum::SUPRA_NATIONAL; return true; }
    if (std::strcmp(str, "SovereignCentralBank") == 0) { out = CollateralEntityTypeEnum::SOVEREIGN_CENTRAL_BANK; return true; }
    if (std::strcmp(str, "QuasiGovernment") == 0) { out = CollateralEntityTypeEnum::QUASI_GOVERNMENT; return true; }
    if (std::strcmp(str, "RegionalGovernment") == 0) { out = CollateralEntityTypeEnum::REGIONAL_GOVERNMENT; return true; }
    if (std::strcmp(str, "Corporate") == 0) { out = CollateralEntityTypeEnum::CORPORATE; return true; }
    if (std::strcmp(str, "Fund") == 0) { out = CollateralEntityTypeEnum::FUND; return true; }
    if (std::strcmp(str, "SpecialPurposeVehicle") == 0) { out = CollateralEntityTypeEnum::SPECIAL_PURPOSE_VEHICLE; return true; }
    return false;
}

/// Represents an enumeration list to identify the type of supranational entity issuing the asset.
enum class SupraNationalIssuerTypeEnum {
    /// Specifies International Financial Institution.
    INTERNATIONAL_ORGANISATION,
    /// Specifies Multilateral Bank or Multilateral Development Bank.
    MULTILATERAL_BANK
};

/// Convert SupraNationalIssuerTypeEnum to its string representation.
inline const char* to_string(SupraNationalIssuerTypeEnum value) {
    switch (value) {
        case SupraNationalIssuerTypeEnum::INTERNATIONAL_ORGANISATION: return "InternationalOrganisation";
        case SupraNationalIssuerTypeEnum::MULTILATERAL_BANK: return "MultilateralBank";
    }
    return "unknown";
}

/// Parse a string into SupraNationalIssuerTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, SupraNationalIssuerTypeEnum& out) {
    if (std::strcmp(str, "InternationalOrganisation") == 0) { out = SupraNationalIssuerTypeEnum::INTERNATIONAL_ORGANISATION; return true; }
    if (std::strcmp(str, "MultilateralBank") == 0) { out = SupraNationalIssuerTypeEnum::MULTILATERAL_BANK; return true; }
    return false;
}

/// Represents an enumeration list to identify tranched or untranched credit risk.
enum class CreditRiskEnum {
    /// Indicates tranched credit risk, including securitizations.
    TRANCHED_CREDIT_RISK,
    /// Indicates tranched credit risk, including repackagings.
    UNTRANCHED_CREDIT_RISK
};

/// Convert CreditRiskEnum to its string representation.
inline const char* to_string(CreditRiskEnum value) {
    switch (value) {
        case CreditRiskEnum::TRANCHED_CREDIT_RISK: return "TranchedCreditRisk";
        case CreditRiskEnum::UNTRANCHED_CREDIT_RISK: return "UntranchedCreditRisk";
    }
    return "unknown";
}

/// Parse a string into CreditRiskEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CreditRiskEnum& out) {
    if (std::strcmp(str, "TranchedCreditRisk") == 0) { out = CreditRiskEnum::TRANCHED_CREDIT_RISK; return true; }
    if (std::strcmp(str, "UntranchedCreditRisk") == 0) { out = CreditRiskEnum::UNTRANCHED_CREDIT_RISK; return true; }
    return false;
}

/// Represents an enumeration list to indentify the type of a security.
enum class SecurityTypeEnum {
    /// Identifies a security as a fixed income security of debt issued and securitized as a tradable asset.
    DEBT,
    /// Identifies a security as an Equity value of holding of shares in listed company.
    EQUITY,
    /// Identifies a security as representing holding in an investment fund.
    FUND,
    /// Identifies a security as a Warrant that give the right, but not the obligation, to buy or sell a security — most commonly an equity — at a certain price before expiration, or to receive the cash equivalent.
    WARRANT,
    /// Identifies a security as one that that offers a derivative-based economic return which is not structured as a bond, an equity or a warrant. Note that this security type is not a Certificate of Deposit (aka CD).
    CERTIFICATE
};

/// Convert SecurityTypeEnum to its string representation.
