    if (std::strcmp(str, "US_CFTC_PRType5B") == 0) { out = USCFTCPREligibleCollateralEnum::US_CFTC_PR_TYPE5_B; return true; }
    if (std::strcmp(str, "US_CFTC_PRType6") == 0) { out = USCFTCPREligibleCollateralEnum::US_CFTC_PR_TYPE6; return true; }
