    if (std::strcmp(str, "US_CFTC_PRType8B") == 0) { out = USCFTCPREligibleCollateralEnum::US_CFTC_PR_TYPE8_B; return true; }
    if (std::strcmp(str, "US_CFTC_PRType8C") == 0) { out = USCFTCPREligibleCollateralEnum::US_CFTC_PR_TYPE8_C; return true; }
    if (std::strcmp(str, "US_CFTC_PRType9") == 0) { out = USCFTCPREligibleCollateralEnum::US_CFTC_PR_TYPE9; return true; }
