/// The enumerated values used in both the obligations and deliverable obligations of the credit default swap to represent a class or type of securities which apply.
enum class ObligationCategoryEnum {
    /// ISDA term 'Payment'.
    PAYMENT,
    /// ISDA term 'Borrowed Money'.
    BORROWED_MONEY,
    /// ISDA term 'Reference Obligations Only'.
    REFERENCE_OBLIGATIONS_ONLY,
    /// ISDA term 'Bond'.
    BOND,
    /// ISDA term 'Loan'.
    LOAN,
    /// ISDA term 'Bond or Loan'.
    BOND_OR_LOAN
};

/// Convert ObligationCategoryEnum to its string representation.
inline const char* to_string(ObligationCategoryEnum value) {
    switch (value) {
        case ObligationCategoryEnum::PAYMENT: return "Payment";
        case ObligationCategoryEnum::BORROWED_MONEY: return "BorrowedMoney";
        case ObligationCategoryEnum::REFERENCE_OBLIGATIONS_ONLY: return "ReferenceObligationsOnly";
        case ObligationCategoryEnum::BOND: return "Bond";
        case ObligationCategoryEnum::LOAN: return "Loan";
        case ObligationCategoryEnum::BOND_OR_LOAN: return "BondOrLoan";
    }
    return "unknown";
}

/// Parse a string into ObligationCategoryEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, ObligationCategoryEnum& out) {
    if (std::strcmp(str, "Payment") == 0) { out = ObligationCategoryEnum::PAYMENT; return true; }
    if (std::strcmp(str, "BorrowedMoney") == 0) { out = ObligationCategoryEnum::BORROWED_MONEY; return true; }
    if (std::strcmp(str, "ReferenceObligationsOnly") == 0) { out = ObligationCategoryEnum::REFERENCE_OBLIGATIONS_ONLY; return true; }
    if (std::strcmp(str, "Bond") == 0) { out = ObligationCategoryEnum::BOND; return true; }
    if (std::strcmp(str, "Loan") == 0) { out = ObligationCategoryEnum::LOAN; return true; }
    if (std::strcmp(str, "BondOrLoan") == 0) { out = ObligationCategoryEnum::BOND_OR_LOAN; return true; }
    return false;
}

