/// Defines the enumerated values to specify the ancillary roles to the transaction. The product is agnostic to the actual parties involved in the transaction, with the party references abstracted away from the product definition and replaced by the AncillaryRoleEnum. The AncillaryRoleEnum can then be positioned in the product and the AncillaryParty type, which is positioned outside of the product definition, allows the AncillaryRoleEnum to be associated with an actual party reference.
enum class AncillaryRoleEnum {
    /// Specifies the party which determines additional disruption events.
    DISRUPTION_EVENTS_DETERMINING_PARTY,
    /// Specifies the party which determines if dividends are extraordinary in relation to normal levels.
    EXTRAORDINARY_DIVIDENDS_PARTY,
    /// Specifies the clearing organization (CCP, DCO) which the trade should be cleared.
    PREDETERMINED_CLEARING_ORGANIZATION_PARTY,
    /// Specifies the party to which notice of a manual exercise should be given.
    EXERCISE_NOTICE_RECEIVER_PARTY_MANUAL,
    /// Specifies the party to which notice of a optional early termination exercise should be given.
    EXERCISE_NOTICE_RECEIVER_PARTY_OPTIONAL_EARLY_TERMINATION,
    /// Specifies the party to which notice of a cancelable provision exercise should be given.
    EXERCISE_NOTICE_RECEIVER_PARTY_CANCELABLE_PROVISION,
    /// Specifies the party to which notice of a extendible provision exercise should be given.
    EXERCISE_NOTICE_RECEIVER_PARTY_EXTENDIBLE_PROVISION,
    /// Specifies the party responsible for performing calculation agent duties as defined in the applicable product definition.
    CALCULATION_AGENT_INDEPENDENT,
    /// Specifies the party responsible for performing calculation agent duties associated with an optional early termination.
    CALCULATION_AGENT_OPTIONAL_EARLY_TERMINATION,
    /// Specifies the party responsible for performing calculation agent duties associated with an mandatory early termination.
    CALCULATION_AGENT_MANDATORY_EARLY_TERMINATION,
    /// Specifies the party responsible for deciding the fallback rate.
    CALCULATION_AGENT_FALLBACK
};

/// Convert AncillaryRoleEnum to its string representation.
inline const char* to_string(AncillaryRoleEnum value) {
    switch (value) {
        case AncillaryRoleEnum::DISRUPTION_EVENTS_DETERMINING_PARTY: return "DisruptionEventsDeterminingParty";
        case AncillaryRoleEnum::EXTRAORDINARY_DIVIDENDS_PARTY: return "ExtraordinaryDividendsParty";
        case AncillaryRoleEnum::PREDETERMINED_CLEARING_ORGANIZATION_PARTY: return "PredeterminedClearingOrganizationParty";
        case AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_MANUAL: return "ExerciseNoticeReceiverPartyManual";
        case AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_OPTIONAL_EARLY_TERMINATION: return "ExerciseNoticeReceiverPartyOptionalEarlyTermination";
        case AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_CANCELABLE_PROVISION: return "ExerciseNoticeReceiverPartyCancelableProvision";
        case AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_EXTENDIBLE_PROVISION: return "ExerciseNoticeReceiverPartyExtendibleProvision";
        case AncillaryRoleEnum::CALCULATION_AGENT_INDEPENDENT: return "CalculationAgentIndependent";
        case AncillaryRoleEnum::CALCULATION_AGENT_OPTIONAL_EARLY_TERMINATION: return "CalculationAgentOptionalEarlyTermination";
        case AncillaryRoleEnum::CALCULATION_AGENT_MANDATORY_EARLY_TERMINATION: return "CalculationAgentMandatoryEarlyTermination";
        case AncillaryRoleEnum::CALCULATION_AGENT_FALLBACK: return "CalculationAgentFallback";
    }
    return "unknown";
}

/// Parse a string into AncillaryRoleEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AncillaryRoleEnum& out) {
    if (std::strcmp(str, "DisruptionEventsDeterminingParty") == 0) { out = AncillaryRoleEnum::DISRUPTION_EVENTS_DETERMINING_PARTY; return true; }
    if (std::strcmp(str, "ExtraordinaryDividendsParty") == 0) { out = AncillaryRoleEnum::EXTRAORDINARY_DIVIDENDS_PARTY; return true; }
    if (std::strcmp(str, "PredeterminedClearingOrganizationParty") == 0) { out = AncillaryRoleEnum::PREDETERMINED_CLEARING_ORGANIZATION_PARTY; return true; }
    if (std::strcmp(str, "ExerciseNoticeReceiverPartyManual") == 0) { out = AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_MANUAL; return true; }
    if (std::strcmp(str, "ExerciseNoticeReceiverPartyOptionalEarlyTermination") == 0) { out = AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_OPTIONAL_EARLY_TERMINATION; return true; }
    if (std::strcmp(str, "ExerciseNoticeReceiverPartyCancelableProvision") == 0) { out = AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_CANCELABLE_PROVISION; return true; }
    if (std::strcmp(str, "ExerciseNoticeReceiverPartyExtendibleProvision") == 0) { out = AncillaryRoleEnum::EXERCISE_NOTICE_RECEIVER_PARTY_EXTENDIBLE_PROVISION; return true; }
    if (std::strcmp(str, "CalculationAgentIndependent") == 0) { out = AncillaryRoleEnum::CALCULATION_AGENT_INDEPENDENT; return true; }
    if (std::strcmp(str, "CalculationAgentOptionalEarlyTermination") == 0) { out = AncillaryRoleEnum::CALCULATION_AGENT_OPTIONAL_EARLY_TERMINATION; return true; }
    if (std::strcmp(str, "CalculationAgentMandatoryEarlyTermination") == 0) { out = AncillaryRoleEnum::CALCULATION_AGENT_MANDATORY_EARLY_TERMINATION; return true; }
    if (std::strcmp(str, "CalculationAgentFallback") == 0) { out = AncillaryRoleEnum::CALCULATION_AGENT_FALLBACK; return true; }
    return false;
}

/// The enumerated values to specify the type of telephone number, e.g. work vs. mobile.
enum class TelephoneTypeEnum {
    /// A number used primarily for work-related calls. Includes home office numbers used primarily for work purposes.
    WORK,
    /// A number on a mobile telephone that is often or usually used for work-related calls. This type of number can be used for urgent work related business when a work number is not sufficient to contact the person or firm.
    MOBILE,
    /// A number used primarily for work-related facsimile transmissions.
    FAX,
    /// A number used primarily for non work-related calls. (Normally this type of number would be used only as an emergency backup number, not as a regular course of business).
    PERSONAL
};

/// Convert TelephoneTypeEnum to its string representation.
inline const char* to_string(TelephoneTypeEnum value) {
    switch (value) {
        case TelephoneTypeEnum::WORK: return "Work";
        case TelephoneTypeEnum::MOBILE: return "Mobile";
        case TelephoneTypeEnum::FAX: return "Fax";
        case TelephoneTypeEnum::PERSONAL: return "Personal";
    }
    return "unknown";
}

/// Parse a string into TelephoneTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, TelephoneTypeEnum& out) {
    if (std::strcmp(str, "Work") == 0) { out = TelephoneTypeEnum::WORK; return true; }
    if (std::strcmp(str, "Mobile") == 0) { out = TelephoneTypeEnum::MOBILE; return true; }
    if (std::strcmp(str, "Fax") == 0) { out = TelephoneTypeEnum::FAX; return true; }
    if (std::strcmp(str, "Personal") == 0) { out = TelephoneTypeEnum::PERSONAL; return true; }
    return false;
}

