    if (std::strcmp(str, "StockNameChange") == 0) { out = CorporateActionTypeEnum::STOCK_NAME_CHANGE; return true; }
    if (std::strcmp(str, "StockIdentifierChange") == 0) { out = CorporateActionTypeEnum::STOCK_IDENTIFIER_CHANGE; return true; }
    if (std::strcmp(str, "RightsIssue") == 0) { out = CorporateActionTypeEnum::RIGHTS_ISSUE; return true; }
    if (std::strcmp(str, "Takeover") == 0) { out = CorporateActionTypeEnum::TAKEOVER; return true; }
