/// The enumerated values to specify what led to the contract or execution closure.
enum class ClosedStateEnum {
    /// The execution or contract has been allocated.
    ALLOCATED,
    /// The execution or contract has been cancelled.
    CANCELLED,
    /// The (option) contract has been exercised.
    EXERCISED,
    /// The (option) contract has expired without being exercised.
    EXPIRED,
    /// The contract has reached its contractual termination date.
    MATURED,
    /// The contract has been novated. This state applies to the stepped-out contract component of the novation event.
    NOVATED,
    /// The contract has been subject of an early termination event.
    TERMINATED
};

/// Convert ClosedStateEnum to its string representation.
inline const char* to_string(ClosedStateEnum value) {
    switch (value) {
        case ClosedStateEnum::ALLOCATED: return "Allocated";
        case ClosedStateEnum::CANCELLED: return "Cancelled";
        case ClosedStateEnum::EXERCISED: return "Exercised";
        case ClosedStateEnum::EXPIRED: return "Expired";
        case ClosedStateEnum::MATURED: return "Matured";
        case ClosedStateEnum::NOVATED: return "Novated";
        case ClosedStateEnum::TERMINATED: return "Terminated";
    }
    return "unknown";
}

/// Parse a string into ClosedStateEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, ClosedStateEnum& out) {
    if (std::strcmp(str, "Allocated") == 0) { out = ClosedStateEnum::ALLOCATED; return true; }
    if (std::strcmp(str, "Cancelled") == 0) { out = ClosedStateEnum::CANCELLED; return true; }
    if (std::strcmp(str, "Exercised") == 0) { out = ClosedStateEnum::EXERCISED; return true; }
    if (std::strcmp(str, "Expired") == 0) { out = ClosedStateEnum::EXPIRED; return true; }
    if (std::strcmp(str, "Matured") == 0) { out = ClosedStateEnum::MATURED; return true; }
    if (std::strcmp(str, "Novated") == 0) { out = ClosedStateEnum::NOVATED; return true; }
    if (std::strcmp(str, "Terminated") == 0) { out = ClosedStateEnum::TERMINATED; return true; }
    return false;
}

/// Enumeration to describe the different (risk) states of a Position, whether executed, settled, matured...etc
enum class PositionStatusEnum {
    /// The position has been executed, which is the point at which risk has been transferred.
    EXECUTED,
    /// Contract has been formed, in case position is on a contractual product.
    FORMED,
    /// The position has settled, in case product is subject to settlement after execution, such as securities.
    SETTLED,
    /// The position has been cancelled, in case of a cancellation event following an execution.
    CANCELLED,
    /// The position has been closed, in case of a termination event.
    CLOSED
};

/// Convert PositionStatusEnum to its string representation.
inline const char* to_string(PositionStatusEnum value) {
    switch (value) {
        case PositionStatusEnum::EXECUTED: return "Executed";
        case PositionStatusEnum::FORMED: return "Formed";
        case PositionStatusEnum::SETTLED: return "Settled";
        case PositionStatusEnum::CANCELLED: return "Cancelled";
        case PositionStatusEnum::CLOSED: return "Closed";
    }
    return "unknown";
}

/// Parse a string into PositionStatusEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, PositionStatusEnum& out) {
    if (std::strcmp(str, "Executed") == 0) { out = PositionStatusEnum::EXECUTED; return true; }
    if (std::strcmp(str, "Formed") == 0) { out = PositionStatusEnum::FORMED; return true; }
    if (std::strcmp(str, "Settled") == 0) { out = PositionStatusEnum::SETTLED; return true; }
    if (std::strcmp(str, "Cancelled") == 0) { out = PositionStatusEnum::CANCELLED; return true; }
    if (std::strcmp(str, "Closed") == 0) { out = PositionStatusEnum::CLOSED; return true; }
    return false;
}

