/// The enumeration values to qualify the timestamps that can be associated with a lifecycle event. The reason for such approach is that the experience of integrating the DTCC and CME data representations suggests that a wide set of timestamps are currently utilized among service providers, while there is not at present an objective set of criteria that could help suggest a defined set of timestamps as part of the CDM. Implementers are expected to evaluate the current enumeration values to determine whether those meet their requirements. If not, they are expected to engage with the CDM team to evaluate the addition of further value(s) to this enumeration, which will then participate to the development of a compendium for further evaluation at a later point in order to determine whether this modeling is appropriate.
enum class EventTimestampQualificationEnum {
    /// The date and time on the trade was cleared.
    CLEARING_DATE_TIME,
    /// The date and time on which trade was confirmed as cleared.
    CLEARING_CONFIRMATION_DATE_TIME,
    /// The date and time on which trade was received by Clearing Body.
    CLEARING_RECEIPT_DATE_TIME,
    /// The date and time on which the event was submitted for clearing.
    CLEARING_SUBMISSION_DATE_TIME,
    /// The date and time on which the event was confirmed.
    CONFIRMATION_DATE_TIME,
    /// The date and time on which the event was created.
    EVENT_CREATION_DATE_TIME,
    /// The date and time on which the event will be considered expired.
    EVENT_EXPIRATION_DATE_TIME,
    /// The date and time on which the event was processed.
    EVENT_PROCESSING_DATE_TIME,
    /// The date and time on which the event was sent.
    EVENT_SENT_DATE_TIME,
    /// The date and time on which the event was submitted.
    EVENT_SUBMITTED_DATE_TIME,
    /// The date and time on which the trade execution was performed.
    EXECUTION_DATE_TIME,
    /// The date and time on which the transaction has been created. This timestamp is specified as such by the CME ClearPort Matched IRS Trade submission API specification: 'The transaction date time of the trade. Represents the date & time on which the trade was initially generated either by CME Clearing or firm. The transaction date time may be assigned by CME Clearing at the point the trade is reported as cleared. Transaction date time can also be provided by an external submitter of the trade at the point the trade is submitted.'
    TRANSACTION_CREATION_DATE_TIME
};

/// Convert EventTimestampQualificationEnum to its string representation.
inline const char* to_string(EventTimestampQualificationEnum value) {
    switch (value) {
        case EventTimestampQualificationEnum::CLEARING_DATE_TIME: return "clearingDateTime";
        case EventTimestampQualificationEnum::CLEARING_CONFIRMATION_DATE_TIME: return "clearingConfirmationDateTime";
        case EventTimestampQualificationEnum::CLEARING_RECEIPT_DATE_TIME: return "clearingReceiptDateTime";
        case EventTimestampQualificationEnum::CLEARING_SUBMISSION_DATE_TIME: return "clearingSubmissionDateTime";
        case EventTimestampQualificationEnum::CONFIRMATION_DATE_TIME: return "confirmationDateTime";
        case EventTimestampQualificationEnum::EVENT_CREATION_DATE_TIME: return "eventCreationDateTime";
        case EventTimestampQualificationEnum::EVENT_EXPIRATION_DATE_TIME: return "eventExpirationDateTime";
        case EventTimestampQualificationEnum::EVENT_PROCESSING_DATE_TIME: return "eventProcessingDateTime";
        case EventTimestampQualificationEnum::EVENT_SENT_DATE_TIME: return "eventSentDateTime";
        case EventTimestampQualificationEnum::EVENT_SUBMITTED_DATE_TIME: return "eventSubmittedDateTime";
        case EventTimestampQualificationEnum::EXECUTION_DATE_TIME: return "executionDateTime";
        case EventTimestampQualificationEnum::TRANSACTION_CREATION_DATE_TIME: return "transactionCreationDateTime";
    }
    return "unknown";
}

/// Parse a string into EventTimestampQualificationEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, EventTimestampQualificationEnum& out) {
    if (std::strcmp(str, "clearingDateTime") == 0) { out = EventTimestampQualificationEnum::CLEARING_DATE_TIME; return true; }
    if (std::strcmp(str, "clearingConfirmationDateTime") == 0) { out = EventTimestampQualificationEnum::CLEARING_CONFIRMATION_DATE_TIME; return true; }
    if (std::strcmp(str, "clearingReceiptDateTime") == 0) { out = EventTimestampQualificationEnum::CLEARING_RECEIPT_DATE_TIME; return true; }
    if (std::strcmp(str, "clearingSubmissionDateTime") == 0) { out = EventTimestampQualificationEnum::CLEARING_SUBMISSION_DATE_TIME; return true; }
    if (std::strcmp(str, "confirmationDateTime") == 0) { out = EventTimestampQualificationEnum::CONFIRMATION_DATE_TIME; return true; }
    if (std::strcmp(str, "eventCreationDateTime") == 0) { out = EventTimestampQualificationEnum::EVENT_CREATION_DATE_TIME; return true; }
    if (std::strcmp(str, "eventExpirationDateTime") == 0) { out = EventTimestampQualificationEnum::EVENT_EXPIRATION_DATE_TIME; return true; }
    if (std::strcmp(str, "eventProcessingDateTime") == 0) { out = EventTimestampQualificationEnum::EVENT_PROCESSING_DATE_TIME; return true; }
    if (std::strcmp(str, "eventSentDateTime") == 0) { out = EventTimestampQualificationEnum::EVENT_SENT_DATE_TIME; return true; }
    if (std::strcmp(str, "eventSubmittedDateTime") == 0) { out = EventTimestampQualificationEnum::EVENT_SUBMITTED_DATE_TIME; return true; }
    if (std::strcmp(str, "executionDateTime") == 0) { out = EventTimestampQualificationEnum::EXECUTION_DATE_TIME; return true; }
    if (std::strcmp(str, "transactionCreationDateTime") == 0) { out = EventTimestampQualificationEnum::TRANSACTION_CREATION_DATE_TIME; return true; }
    return false;
}

/// The enumeration values to specify the level at which the limit is set: customer business, proprietary business or account level. This is part of the CME specification for clearing credit limits, although not specified as a set of enumerated values as part of the clearing confirmation specification.
enum class LimitLevelEnum {
    /// The limit is set in relation to the proprietary business undertaken by the clearing counterparty.
    ACCOUNT,
    /// The limit is set in relation to the customer business undertaken by the clearing counterparty.
    CUSTOMER,
    /// The limit is set at the account level in relation to the clearing counterparty.
    HOUSE
};

/// Convert LimitLevelEnum to its string representation.
inline const char* to_string(LimitLevelEnum value) {
    switch (value) {
        case LimitLevelEnum::ACCOUNT: return "Account";
        case LimitLevelEnum::CUSTOMER: return "Customer";
        case LimitLevelEnum::HOUSE: return "House";
    }
    return "unknown";
}

/// Parse a string into LimitLevelEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, LimitLevelEnum& out) {
    if (std::strcmp(str, "Account") == 0) { out = LimitLevelEnum::ACCOUNT; return true; }
    if (std::strcmp(str, "Customer") == 0) { out = LimitLevelEnum::CUSTOMER; return true; }
    if (std::strcmp(str, "House") == 0) { out = LimitLevelEnum::HOUSE; return true; }
    return false;
}

