/// Values to specify the margin approach specific to Initial Margin agreements.
enum class MarginApproachEnum {
    /// Distinct Margin Flow (IM) Approach.
    DISTINCT,
    /// Allocated Margin Flow (IM/IA) Approach.
    ALLOCATED,
    /// Greater of Margin Flow (IM/IA) Approach.
    GREATER_OF
};

/// Convert MarginApproachEnum to its string representation.
inline const char* to_string(MarginApproachEnum value) {
    switch (value) {
        case MarginApproachEnum::DISTINCT: return "Distinct";
        case MarginApproachEnum::ALLOCATED: return "Allocated";
        case MarginApproachEnum::GREATER_OF: return "GreaterOf";
    }
    return "unknown";
}

/// Parse a string into MarginApproachEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, MarginApproachEnum& out) {
    if (std::strcmp(str, "Distinct") == 0) { out = MarginApproachEnum::DISTINCT; return true; }
    if (std::strcmp(str, "Allocated") == 0) { out = MarginApproachEnum::ALLOCATED; return true; }
    if (std::strcmp(str, "GreaterOf") == 0) { out = MarginApproachEnum::GREATER_OF; return true; }
    return false;
}

