/// The enumerated values to specify the effective date of the Amendment to Termination Currency when specified as a specific date (e.g. the annex date).
enum class AmendmentEffectiveDateEnum {
    /// The effective date corresponds to the Annex date.
    ANNEX_DATE,
    /// The effective date corresponds to the Deed date.
    DEED_DATE,
    /// The effective date corresponds to the Agreement date.
    AGREEMENT_DATE,
    /// The effective date corresponds to the Amendment Effective Date (IM).
    AMENDMENT_EFFECTIVE_DATE
};

/// Convert AmendmentEffectiveDateEnum to its string representation.
inline const char* to_string(AmendmentEffectiveDateEnum value) {
    switch (value) {
        case AmendmentEffectiveDateEnum::ANNEX_DATE: return "AnnexDate";
        case AmendmentEffectiveDateEnum::DEED_DATE: return "DeedDate";
        case AmendmentEffectiveDateEnum::AGREEMENT_DATE: return "AgreementDate";
        case AmendmentEffectiveDateEnum::AMENDMENT_EFFECTIVE_DATE: return "AmendmentEffectiveDate";
    }
    return "unknown";
}

/// Parse a string into AmendmentEffectiveDateEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AmendmentEffectiveDateEnum& out) {
    if (std::strcmp(str, "AnnexDate") == 0) { out = AmendmentEffectiveDateEnum::ANNEX_DATE; return true; }
    if (std::strcmp(str, "DeedDate") == 0) { out = AmendmentEffectiveDateEnum::DEED_DATE; return true; }
    if (std::strcmp(str, "AgreementDate") == 0) { out = AmendmentEffectiveDateEnum::AGREEMENT_DATE; return true; }
    if (std::strcmp(str, "AmendmentEffectiveDate") == 0) { out = AmendmentEffectiveDateEnum::AMENDMENT_EFFECTIVE_DATE; return true; }
    return false;
}

