/// Specifies the types of events in the related Master Agreement that, when triggered, could temporarily or permanently suspend rights to rehypothecate, transfer or substitute collateral.
enum class CSASpecifiedOrAccessConditionEnum {
    /// Specifies an event where a party is unable to comply with its obligations under the Master Agreement because to do so would be unlawful.
    ILLEGALITY,
    /// Specifies an event where a party experiences changes in tax laws incurring further tax liability.
    TAX_EVENT,
    /// Specifies an event where a party incurs tax liability due to a merger.
    TAX_EVENT_UPON_MERGER,
    /// Specifies an event where a party merges and the new entity becomes materially less creditworthy than the original.
    CREDIT_EVENT_UPON_MERGER,
    /// Specifies events which could trigger rights to early termination.
    ADDITIONAL_TERMINATION_EVENTS,
    /// Specifies an event beyond the control of one or both of the parties which prevents or renders it impossible to fulfill their obligations to the other party.
    FORCE_MAJEURE_EVENT,
    /// Specifies a potential event that could trigger rights to early termination.
    POTENTIAL_TERMINATION_EVENTS
};

/// Convert CSASpecifiedOrAccessConditionEnum to its string representation.
inline const char* to_string(CSASpecifiedOrAccessConditionEnum value) {
    switch (value) {
        case CSASpecifiedOrAccessConditionEnum::ILLEGALITY: return "Illegality";
        case CSASpecifiedOrAccessConditionEnum::TAX_EVENT: return "TaxEvent";
        case CSASpecifiedOrAccessConditionEnum::TAX_EVENT_UPON_MERGER: return "TaxEventUponMerger";
        case CSASpecifiedOrAccessConditionEnum::CREDIT_EVENT_UPON_MERGER: return "CreditEventUponMerger";
        case CSASpecifiedOrAccessConditionEnum::ADDITIONAL_TERMINATION_EVENTS: return "AdditionalTerminationEvents";
        case CSASpecifiedOrAccessConditionEnum::FORCE_MAJEURE_EVENT: return "ForceMajeureEvent";
        case CSASpecifiedOrAccessConditionEnum::POTENTIAL_TERMINATION_EVENTS: return "PotentialTerminationEvents";
    }
    return "unknown";
}

/// Parse a string into CSASpecifiedOrAccessConditionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CSASpecifiedOrAccessConditionEnum& out) {
    if (std::strcmp(str, "Illegality") == 0) { out = CSASpecifiedOrAccessConditionEnum::ILLEGALITY; return true; }
    if (std::strcmp(str, "TaxEvent") == 0) { out = CSASpecifiedOrAccessConditionEnum::TAX_EVENT; return true; }
    if (std::strcmp(str, "TaxEventUponMerger") == 0) { out = CSASpecifiedOrAccessConditionEnum::TAX_EVENT_UPON_MERGER; return true; }
    if (std::strcmp(str, "CreditEventUponMerger") == 0) { out = CSASpecifiedOrAccessConditionEnum::CREDIT_EVENT_UPON_MERGER; return true; }
    if (std::strcmp(str, "AdditionalTerminationEvents") == 0) { out = CSASpecifiedOrAccessConditionEnum::ADDITIONAL_TERMINATION_EVENTS; return true; }
    if (std::strcmp(str, "ForceMajeureEvent") == 0) { out = CSASpecifiedOrAccessConditionEnum::FORCE_MAJEURE_EVENT; return true; }
    if (std::strcmp(str, "PotentialTerminationEvents") == 0) { out = CSASpecifiedOrAccessConditionEnum::POTENTIAL_TERMINATION_EVENTS; return true; }
    return false;
}

/// Specifies the types of events found in the related Master Agreement that may lead to the early termination of the Master Agreement, including suspension of the affected party's rights to rehypothecate, transfer, or substitute collateral.
enum class AdditionalTerminationEventEnum {
    /// Specifies an event where a party fails to notify the other of a decline in Net Asset Value by a specified amount over a specified period of time.
    FAILURE_TO_NOTIFY_NAV,
    /// Specifies an event where the investment advisor of a party ceases to act for the party.
    INVESTMENT_ADVISOR,
    /// Specifies an event where a person deemed important to a party has departed.
    KEY_PERSONS,
    /// Specifies an event in which a partys Net Asset Value (NAV) has declined beyond a specified percentage or amount within a defined time period.
    NAV_DECLINE_TRIGGER,
    /// Specifies an event in which a partys Net Asset Value (NAV) falls below a predetermined absolute value, regardless of the timeframe over which the decline occurs. This value sets a minimum acceptable NAV threshold expressed as either a percentage or amount.
    NAV_FLOOR,
    /// Specifies an event where a party delivers operative documents that are invalid, untrue or unenforceable.
    OPERATIVE_DOCS,
    /// Specifies an event where Party 1 experiences a downgrade beyond a predetermined level, or has their credit rating withdrawn or suspended.
    RATINGS_DOWNGRADE_OR_WITHDRAWAL_PARTY1,
    /// Specifies an event where Party 2 experiences a downgrade beyond a predetermined level, or has their credit rating withdrawn or suspended.
    RATINGS_DOWNGRADE_OR_WITHDRAWAL_PARTY2,
    /// Represents the Additional Termination Event(s) in the related Master Agreement.
    AS_APPLICABLE,
    /// Represents any bespoke Additional Termination Event(s) that are set out in the related Specified Condition clause.
    AS_SPECIFIED
};

/// Convert AdditionalTerminationEventEnum to its string representation.
inline const char* to_string(AdditionalTerminationEventEnum value) {
    switch (value) {
        case AdditionalTerminationEventEnum::FAILURE_TO_NOTIFY_NAV: return "FailureToNotifyNAV";
        case AdditionalTerminationEventEnum::INVESTMENT_ADVISOR: return "InvestmentAdvisor";
        case AdditionalTerminationEventEnum::KEY_PERSONS: return "KeyPersons";
        case AdditionalTerminationEventEnum::NAV_DECLINE_TRIGGER: return "NAVDeclineTrigger";
        case AdditionalTerminationEventEnum::NAV_FLOOR: return "NAVFloor";
        case AdditionalTerminationEventEnum::OPERATIVE_DOCS: return "OperativeDocs";
        case AdditionalTerminationEventEnum::RATINGS_DOWNGRADE_OR_WITHDRAWAL_PARTY1: return "RatingsDowngradeOrWithdrawalParty1";
        case AdditionalTerminationEventEnum::RATINGS_DOWNGRADE_OR_WITHDRAWAL_PARTY2: return "RatingsDowngradeOrWithdrawalParty2";
        case AdditionalTerminationEventEnum::AS_APPLICABLE: return "AsApplicable";
        case AdditionalTerminationEventEnum::AS_SPECIFIED: return "AsSpecified";
    }
    return "unknown";
}

/// Parse a string into AdditionalTerminationEventEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AdditionalTerminationEventEnum& out) {
    if (std::strcmp(str, "FailureToNotifyNAV") == 0) { out = AdditionalTerminationEventEnum::FAILURE_TO_NOTIFY_NAV; return true; }
    if (std::strcmp(str, "InvestmentAdvisor") == 0) { out = AdditionalTerminationEventEnum::INVESTMENT_ADVISOR; return true; }
    if (std::strcmp(str, "KeyPersons") == 0) { out = AdditionalTerminationEventEnum::KEY_PERSONS; return true; }
    if (std::strcmp(str, "NAVDeclineTrigger") == 0) { out = AdditionalTerminationEventEnum::NAV_DECLINE_TRIGGER; return true; }
    if (std::strcmp(str, "NAVFloor") == 0) { out = AdditionalTerminationEventEnum::NAV_FLOOR; return true; }
    if (std::strcmp(str, "OperativeDocs") == 0) { out = AdditionalTerminationEventEnum::OPERATIVE_DOCS; return true; }
    if (std::strcmp(str, "RatingsDowngradeOrWithdrawalParty1") == 0) { out = AdditionalTerminationEventEnum::RATINGS_DOWNGRADE_OR_WITHDRAWAL_PARTY1; return true; }
    if (std::strcmp(str, "RatingsDowngradeOrWithdrawalParty2") == 0) { out = AdditionalTerminationEventEnum::RATINGS_DOWNGRADE_OR_WITHDRAWAL_PARTY2; return true; }
    if (std::strcmp(str, "AsApplicable") == 0) { out = AdditionalTerminationEventEnum::AS_APPLICABLE; return true; }
    if (std::strcmp(str, "AsSpecified") == 0) { out = AdditionalTerminationEventEnum::AS_SPECIFIED; return true; }
    return false;
}

