/// Parse a string into MasterConfirmationAnnexTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, MasterConfirmationAnnexTypeEnum& out) {
    if (std::strcmp(str, "ISDA2004IndexVarianceSwapAmericasInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2004_INDEX_VARIANCE_SWAP_AMERICAS_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2004ShareVarianceSwapAmericasInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2004_SHARE_VARIANCE_SWAP_AMERICAS_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2007DispersionVarianceSwapEuropean") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2007_DISPERSION_VARIANCE_SWAP_EUROPEAN; return true; }
    if (std::strcmp(str, "ISDA2007EquityFinanceSwapEuropean") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2007_EQUITY_FINANCE_SWAP_EUROPEAN; return true; }
    if (std::strcmp(str, "ISDA2007IndexVarianceSwapAmericasInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2007_INDEX_VARIANCE_SWAP_AMERICAS_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2007ShareVarianceSwapAmericasInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2007_SHARE_VARIANCE_SWAP_AMERICAS_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2007VarianceOptionEuropean") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2007_VARIANCE_OPTION_EUROPEAN; return true; }
    if (std::strcmp(str, "ISDA2008EquityFinanceSwapAsiaExcludingJapan") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2008_EQUITY_FINANCE_SWAP_ASIA_EXCLUDING_JAPAN; return true; }
    if (std::strcmp(str, "ISDA2008EquityFinanceSwapAsiaExcludingJapanRev1") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2008_EQUITY_FINANCE_SWAP_ASIA_EXCLUDING_JAPAN_REV1; return true; }
    if (std::strcmp(str, "ISDA2008EquityOptionAsiaExcludingJapan") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2008_EQUITY_OPTION_ASIA_EXCLUDING_JAPAN; return true; }
    if (std::strcmp(str, "ISDA2008EquityOptionAsiaExcludingJapanRev1") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2008_EQUITY_OPTION_ASIA_EXCLUDING_JAPAN_REV1; return true; }
    if (std::strcmp(str, "ISDA2008EquityOptionJapan") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2008_EQUITY_OPTION_JAPAN; return true; }
    if (std::strcmp(str, "ISDA2009ClosedMarketsOptionsAsiaExcludingJapan") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_CLOSED_MARKETS_OPTIONS_ASIA_EXCLUDING_JAPAN; return true; }
    if (std::strcmp(str, "ISDA2009EquityEuropeanInterdealerSS") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_EQUITY_EUROPEAN_INTERDEALER_SS; return true; }
    if (std::strcmp(str, "ISDA2009EquityEuropeanIS") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_EQUITY_EUROPEAN_IS; return true; }
    if (std::strcmp(str, "ISDA2009IndexShareOptionAmericas") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_INDEX_SHARE_OPTION_AMERICAS; return true; }
    if (std::strcmp(str, "ISDA2009IndexSwapEuropeanInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_INDEX_SWAP_EUROPEAN_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2009IndexSwapPanAsiaInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_INDEX_SWAP_PAN_ASIA_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2009ShareSwapPanAsia") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2009_SHARE_SWAP_PAN_ASIA; return true; }
    if (std::strcmp(str, "ISDA2010FairValueShareSwapEuropeanInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2010_FAIR_VALUE_SHARE_SWAP_EUROPEAN_INTERDEALER; return true; }
    if (std::strcmp(str, "ISDA2010IndexShareOptionEMEAInterdealer") == 0) { out = MasterConfirmationAnnexTypeEnum::ISDA2010_INDEX_SHARE_OPTION_EMEA_INTERDEALER; return true; }
    return false;
}

/// Defines the consequences of nationalization, insolvency and delisting events relating to the underlying.
enum class NationalizationOrInsolvencyOrDelistingEventEnum {
    /// The parties may, but are not obliged, to terminate the transaction on mutually acceptable terms and if the terms are not agreed then the transaction continues.
    NEGOTIATED_CLOSEOUT,
    /// The trade is terminated.
    CANCELLATION_AND_PAYMENT
};

/// Convert NationalizationOrInsolvencyOrDelistingEventEnum to its string representation.
inline const char* to_string(NationalizationOrInsolvencyOrDelistingEventEnum value) {
    switch (value) {
        case NationalizationOrInsolvencyOrDelistingEventEnum::NEGOTIATED_CLOSEOUT: return "NegotiatedCloseout";
        case NationalizationOrInsolvencyOrDelistingEventEnum::CANCELLATION_AND_PAYMENT: return "CancellationAndPayment";
    }
    return "unknown";
}

/// Parse a string into NationalizationOrInsolvencyOrDelistingEventEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, NationalizationOrInsolvencyOrDelistingEventEnum& out) {
    if (std::strcmp(str, "NegotiatedCloseout") == 0) { out = NationalizationOrInsolvencyOrDelistingEventEnum::NEGOTIATED_CLOSEOUT; return true; }
    if (std::strcmp(str, "CancellationAndPayment") == 0) { out = NationalizationOrInsolvencyOrDelistingEventEnum::CANCELLATION_AND_PAYMENT; return true; }
    return false;
}

