/// The potential options for specifying whether a particular election applies in a GMSLA.
enum class ApplicabilityOfElectionEnum {
    /// The election is applicable.
    APPLICABLE,
    /// The election is not applicable.
    NOT_APPLICABLE,
    /// The applicability of the election has not been specified.
    NOT_SPECIFIED
};

/// Convert ApplicabilityOfElectionEnum to its string representation.
inline const char* to_string(ApplicabilityOfElectionEnum value) {
    switch (value) {
        case ApplicabilityOfElectionEnum::APPLICABLE: return "Applicable";
        case ApplicabilityOfElectionEnum::NOT_APPLICABLE: return "NotApplicable";
        case ApplicabilityOfElectionEnum::NOT_SPECIFIED: return "NotSpecified";
    }
    return "unknown";
}

/// Parse a string into ApplicabilityOfElectionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, ApplicabilityOfElectionEnum& out) {
    if (std::strcmp(str, "Applicable") == 0) { out = ApplicabilityOfElectionEnum::APPLICABLE; return true; }
    if (std::strcmp(str, "NotApplicable") == 0) { out = ApplicabilityOfElectionEnum::NOT_APPLICABLE; return true; }
    if (std::strcmp(str, "NotSpecified") == 0) { out = ApplicabilityOfElectionEnum::NOT_SPECIFIED; return true; }
    return false;
}

/// The potential options for specifying whether mark to market value of collateral is determined on an aggregated or loan by loan basis.
enum class AggregationSpecificationEnum {
    /// The market value is determined on an aggregated basis.
    AGGREGATED,
    /// The market value is determined on a loan by loan basis.
    LOAN_BY_LOAN,
    /// The market value is determined on an aggregated basis for some loans but on a Loan by Loan basis for others.
    AGGREGATED_AND_LOAN_BY_LOAN,
    /// It is not specified how the market value is determined.
    NOT_SPECIFIED
};

/// Convert AggregationSpecificationEnum to its string representation.
inline const char* to_string(AggregationSpecificationEnum value) {
    switch (value) {
        case AggregationSpecificationEnum::AGGREGATED: return "Aggregated";
        case AggregationSpecificationEnum::LOAN_BY_LOAN: return "LoanByLoan";
        case AggregationSpecificationEnum::AGGREGATED_AND_LOAN_BY_LOAN: return "AggregatedAndLoanByLoan";
        case AggregationSpecificationEnum::NOT_SPECIFIED: return "NotSpecified";
    }
    return "unknown";
}

/// Parse a string into AggregationSpecificationEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AggregationSpecificationEnum& out) {
    if (std::strcmp(str, "Aggregated") == 0) { out = AggregationSpecificationEnum::AGGREGATED; return true; }
    if (std::strcmp(str, "LoanByLoan") == 0) { out = AggregationSpecificationEnum::LOAN_BY_LOAN; return true; }
    if (std::strcmp(str, "AggregatedAndLoanByLoan") == 0) { out = AggregationSpecificationEnum::AGGREGATED_AND_LOAN_BY_LOAN; return true; }
    if (std::strcmp(str, "NotSpecified") == 0) { out = AggregationSpecificationEnum::NOT_SPECIFIED; return true; }
    return false;
}

