/// The enumerated values to specify the actual quotation style (e.g. PointsUpFront, TradedSpread) used to quote a credit default swap fee leg.
enum class QuotationStyleEnum {
    /// When quotation style is 'PointsUpFront', the initialPoints element of the Credit Default Swap feeLeg should be populated
    POINTS_UP_FRONT,
    /// When quotation style is 'TradedSpread', the marketFixedRate element of the Credit Default Swap feeLeg should be populated
    TRADED_SPREAD,
    /// When quotation style is 'Price', the marketPrice element of the Credit Default Swap feeLeg should be populated
    PRICE
};

/// Convert QuotationStyleEnum to its string representation.
inline const char* to_string(QuotationStyleEnum value) {
    switch (value) {
        case QuotationStyleEnum::POINTS_UP_FRONT: return "PointsUpFront";
        case QuotationStyleEnum::TRADED_SPREAD: return "TradedSpread";
        case QuotationStyleEnum::PRICE: return "Price";
    }
    return "unknown";
}

/// Parse a string into QuotationStyleEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, QuotationStyleEnum& out) {
    if (std::strcmp(str, "PointsUpFront") == 0) { out = QuotationStyleEnum::POINTS_UP_FRONT; return true; }
    if (std::strcmp(str, "TradedSpread") == 0) { out = QuotationStyleEnum::TRADED_SPREAD; return true; }
    if (std::strcmp(str, "Price") == 0) { out = QuotationStyleEnum::PRICE; return true; }
    return false;
}

/// The enumerated values to specify the ISDA defined methodology for determining the final price of the reference obligation for purposes of cash settlement.
enum class ValuationMethodEnum {
    MARKET,
    HIGHEST,
    AVERAGE_MARKET,
    AVERAGE_HIGHEST,
    BLENDED_MARKET,
    BLENDED_HIGHEST,
    AVERAGE_BLENDED_MARKET,
    AVERAGE_BLENDED_HIGHEST
};

/// Convert ValuationMethodEnum to its string representation.
inline const char* to_string(ValuationMethodEnum value) {
    switch (value) {
        case ValuationMethodEnum::MARKET: return "Market";
        case ValuationMethodEnum::HIGHEST: return "Highest";
        case ValuationMethodEnum::AVERAGE_MARKET: return "AverageMarket";
        case ValuationMethodEnum::AVERAGE_HIGHEST: return "AverageHighest";
        case ValuationMethodEnum::BLENDED_MARKET: return "BlendedMarket";
        case ValuationMethodEnum::BLENDED_HIGHEST: return "BlendedHighest";
        case ValuationMethodEnum::AVERAGE_BLENDED_MARKET: return "AverageBlendedMarket";
        case ValuationMethodEnum::AVERAGE_BLENDED_HIGHEST: return "AverageBlendedHighest";
    }
    return "unknown";
}

/// Parse a string into ValuationMethodEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, ValuationMethodEnum& out) {
    if (std::strcmp(str, "Market") == 0) { out = ValuationMethodEnum::MARKET; return true; }
    if (std::strcmp(str, "Highest") == 0) { out = ValuationMethodEnum::HIGHEST; return true; }
    if (std::strcmp(str, "AverageMarket") == 0) { out = ValuationMethodEnum::AVERAGE_MARKET; return true; }
    if (std::strcmp(str, "AverageHighest") == 0) { out = ValuationMethodEnum::AVERAGE_HIGHEST; return true; }
    if (std::strcmp(str, "BlendedMarket") == 0) { out = ValuationMethodEnum::BLENDED_MARKET; return true; }
    if (std::strcmp(str, "BlendedHighest") == 0) { out = ValuationMethodEnum::BLENDED_HIGHEST; return true; }
    if (std::strcmp(str, "AverageBlendedMarket") == 0) { out = ValuationMethodEnum::AVERAGE_BLENDED_MARKET; return true; }
    if (std::strcmp(str, "AverageBlendedHighest") == 0) { out = ValuationMethodEnum::AVERAGE_BLENDED_HIGHEST; return true; }
    return false;
}

