/// Represents an enumeration list to identify the characteristics of the rating if there are several agency issue ratings but not equivalent, reference will be made to label characteristics of the rating such as the lowest/highest available.
enum class CreditNotationMismatchResolutionEnum {
    /// Denotes the lowest credit notation if several notations are listed.
    LOWEST,
    /// Denotes the highest credit notation if several notations are listed.
    HIGHEST,
    /// Denotes that a credit notation issued from a defined reference agency is used if several notations are listed.
    REFERENCE_AGENCY,
    /// Denotes the average credit notation if several notations are listed.
    AVERAGE,
    /// Denotes the second best credit notation if several notations are listed.
    SECOND_BEST,
    /// Utilised where bespoke language represents the label characteristics of the rating.
    OTHER
};

/// Convert CreditNotationMismatchResolutionEnum to its string representation.
inline const char* to_string(CreditNotationMismatchResolutionEnum value) {
    switch (value) {
        case CreditNotationMismatchResolutionEnum::LOWEST: return "Lowest";
        case CreditNotationMismatchResolutionEnum::HIGHEST: return "Highest";
        case CreditNotationMismatchResolutionEnum::REFERENCE_AGENCY: return "ReferenceAgency";
        case CreditNotationMismatchResolutionEnum::AVERAGE: return "Average";
        case CreditNotationMismatchResolutionEnum::SECOND_BEST: return "SecondBest";
        case CreditNotationMismatchResolutionEnum::OTHER: return "Other";
    }
    return "unknown";
}

/// Parse a string into CreditNotationMismatchResolutionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CreditNotationMismatchResolutionEnum& out) {
    if (std::strcmp(str, "Lowest") == 0) { out = CreditNotationMismatchResolutionEnum::LOWEST; return true; }
    if (std::strcmp(str, "Highest") == 0) { out = CreditNotationMismatchResolutionEnum::HIGHEST; return true; }
    if (std::strcmp(str, "ReferenceAgency") == 0) { out = CreditNotationMismatchResolutionEnum::REFERENCE_AGENCY; return true; }
    if (std::strcmp(str, "Average") == 0) { out = CreditNotationMismatchResolutionEnum::AVERAGE; return true; }
    if (std::strcmp(str, "SecondBest") == 0) { out = CreditNotationMismatchResolutionEnum::SECOND_BEST; return true; }
    if (std::strcmp(str, "Other") == 0) { out = CreditNotationMismatchResolutionEnum::OTHER; return true; }
    return false;
}

/// Identifies an agency rating as a simple scale boundary of minimum or maximum.
enum class CreditNotationBoundaryEnum {
    /// Denotes a minumum boundary
    MINIMUM,
    /// Denotes a maxiumum boundary
    MAXIMUM
};

/// Convert CreditNotationBoundaryEnum to its string representation.
inline const char* to_string(CreditNotationBoundaryEnum value) {
    switch (value) {
        case CreditNotationBoundaryEnum::MINIMUM: return "Minimum";
        case CreditNotationBoundaryEnum::MAXIMUM: return "Maximum";
    }
    return "unknown";
}

/// Parse a string into CreditNotationBoundaryEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CreditNotationBoundaryEnum& out) {
    if (std::strcmp(str, "Minimum") == 0) { out = CreditNotationBoundaryEnum::MINIMUM; return true; }
    if (std::strcmp(str, "Maximum") == 0) { out = CreditNotationBoundaryEnum::MAXIMUM; return true; }
    return false;
}

/// The enumerated values to specify the interpolation method, e.g. linear.
enum class InterpolationMethodEnum {
    /// Linear Interpolation applicable.
    LINEAR,
    /// Linear Interpolation applicable.
    LINEAR_ZERO_YIELD,
    /// No Interpolation applicable.
    NONE
};

/// Convert InterpolationMethodEnum to its string representation.
inline const char* to_string(InterpolationMethodEnum value) {
    switch (value) {
        case InterpolationMethodEnum::LINEAR: return "Linear";
        case InterpolationMethodEnum::LINEAR_ZERO_YIELD: return "LinearZeroYield";
        case InterpolationMethodEnum::NONE: return "None";
    }
    return "unknown";
}

/// Parse a string into InterpolationMethodEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, InterpolationMethodEnum& out) {
    if (std::strcmp(str, "Linear") == 0) { out = InterpolationMethodEnum::LINEAR; return true; }
    if (std::strcmp(str, "LinearZeroYield") == 0) { out = InterpolationMethodEnum::LINEAR_ZERO_YIELD; return true; }
    if (std::strcmp(str, "None") == 0) { out = InterpolationMethodEnum::NONE; return true; }
    return false;
}

