/// The enumerated values to specify whether an option will trigger or expire depending upon whether the spot rate is above or below the barrier rate.
enum class TriggerTypeEnum {
    /// The underlier price must be equal to or less than the Trigger level.
    EQUAL_OR_LESS,
    /// The underlier price must be equal to or greater than the Trigger level.
    EQUAL_OR_GREATER,
    /// The underlier price must be equal to the Trigger level.
    EQUAL,
    /// The underlier price must be less than the Trigger level.
    LESS,
    /// The underlier price must be greater than the Trigger level.
    GREATER
};

/// Convert TriggerTypeEnum to its string representation.
inline const char* to_string(TriggerTypeEnum value) {
    switch (value) {
        case TriggerTypeEnum::EQUAL_OR_LESS: return "EqualOrLess";
        case TriggerTypeEnum::EQUAL_OR_GREATER: return "EqualOrGreater";
        case TriggerTypeEnum::EQUAL: return "Equal";
        case TriggerTypeEnum::LESS: return "Less";
        case TriggerTypeEnum::GREATER: return "Greater";
    }
    return "unknown";
}

/// Parse a string into TriggerTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, TriggerTypeEnum& out) {
    if (std::strcmp(str, "EqualOrLess") == 0) { out = TriggerTypeEnum::EQUAL_OR_LESS; return true; }
    if (std::strcmp(str, "EqualOrGreater") == 0) { out = TriggerTypeEnum::EQUAL_OR_GREATER; return true; }
    if (std::strcmp(str, "Equal") == 0) { out = TriggerTypeEnum::EQUAL; return true; }
    if (std::strcmp(str, "Less") == 0) { out = TriggerTypeEnum::LESS; return true; }
    if (std::strcmp(str, "Greater") == 0) { out = TriggerTypeEnum::GREATER; return true; }
    return false;
}

