/// The enumerated values to specify the method of calculating payment obligations when a floating rate is negative (either due to a quoted negative floating rate or by operation of a spread that is subtracted from the floating rate).
enum class NegativeInterestRateTreatmentEnum {
    /// Negative Interest Rate Method. Per 2000 ISDA Definitions, Section 6.4 Negative Interest Rates, paragraphs (b) and (c).
    NEGATIVE_INTEREST_RATE_METHOD,
    /// Zero Interest Rate Method. Per 2000 ISDA Definitions, Section 6.4. Negative Interest Rates, paragraphs (d) and (e).
    ZERO_INTEREST_RATE_METHOD,
    /// Per 2021 ISDA Definitions section 6.8.6
    ZERO_INTEREST_RATE_EXCLUDING_SPREAD_METHOD
};

/// Convert NegativeInterestRateTreatmentEnum to its string representation.
inline const char* to_string(NegativeInterestRateTreatmentEnum value) {
    switch (value) {
        case NegativeInterestRateTreatmentEnum::NEGATIVE_INTEREST_RATE_METHOD: return "NegativeInterestRateMethod";
        case NegativeInterestRateTreatmentEnum::ZERO_INTEREST_RATE_METHOD: return "ZeroInterestRateMethod";
        case NegativeInterestRateTreatmentEnum::ZERO_INTEREST_RATE_EXCLUDING_SPREAD_METHOD: return "ZeroInterestRateExcludingSpreadMethod";
    }
    return "unknown";
}

/// Parse a string into NegativeInterestRateTreatmentEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, NegativeInterestRateTreatmentEnum& out) {
    if (std::strcmp(str, "NegativeInterestRateMethod") == 0) { out = NegativeInterestRateTreatmentEnum::NEGATIVE_INTEREST_RATE_METHOD; return true; }
    if (std::strcmp(str, "ZeroInterestRateMethod") == 0) { out = NegativeInterestRateTreatmentEnum::ZERO_INTEREST_RATE_METHOD; return true; }
    if (std::strcmp(str, "ZeroInterestRateExcludingSpreadMethod") == 0) { out = NegativeInterestRateTreatmentEnum::ZERO_INTEREST_RATE_EXCLUDING_SPREAD_METHOD; return true; }
    return false;
}

