/// The enumerated values to specify how to deal with a non standard calculation period within a swap stream.
enum class StubPeriodTypeEnum {
    /// If there is a non regular period remaining it is left shorter than the streams calculation period frequency and placed at the start of the stream.
    SHORT_INITIAL,
    /// If there is a non regular period remaining it is left shorter than the streams calculation period frequency and placed at the end of the stream.
    SHORT_FINAL,
    /// If there is a non regular period remaining it is placed at the start of the stream and combined with the adjacent calculation period to give a long first calculation period.
    LONG_INITIAL,
    /// If there is a non regular period remaining it is placed at the end of the stream and combined with the adjacent calculation period to give a long last calculation period.
    LONG_FINAL
};

/// Convert StubPeriodTypeEnum to its string representation.
inline const char* to_string(StubPeriodTypeEnum value) {
    switch (value) {
        case StubPeriodTypeEnum::SHORT_INITIAL: return "ShortInitial";
        case StubPeriodTypeEnum::SHORT_FINAL: return "ShortFinal";
        case StubPeriodTypeEnum::LONG_INITIAL: return "LongInitial";
        case StubPeriodTypeEnum::LONG_FINAL: return "LongFinal";
    }
    return "unknown";
}

/// Parse a string into StubPeriodTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, StubPeriodTypeEnum& out) {
    if (std::strcmp(str, "ShortInitial") == 0) { out = StubPeriodTypeEnum::SHORT_INITIAL; return true; }
    if (std::strcmp(str, "ShortFinal") == 0) { out = StubPeriodTypeEnum::SHORT_FINAL; return true; }
    if (std::strcmp(str, "LongInitial") == 0) { out = StubPeriodTypeEnum::LONG_INITIAL; return true; }
    if (std::strcmp(str, "LongFinal") == 0) { out = StubPeriodTypeEnum::LONG_FINAL; return true; }
    return false;
}

