/// If there is an alternative to interest amounts, how is it specified?
enum class AlternativeToInterestAmountEnum {
    /// Interest amount is not transferred if transfer would create or increase a delivery amount.
    STANDARD,
    /// The standard calculation of the Interest Amount is replaced with the amount of interest the secured party actually receives in relation to the Cash collateral.
    ACTUAL_AMOUNT_RECEIVED,
    /// Interest amount is not transferred if transfer would create or increase a delivery amount. (This is the 'Standard' provision). However, interest Amount will be transferred if Delivery Amount is below Minimum Transfer Amount.
    TRANSFER_IF_DELIVERY_AMOUNT_BELOW_MTA,
    /// An other alternative option outside these choices that can be described as an alternative provision.
    OTHER
};

/// Convert AlternativeToInterestAmountEnum to its string representation.
inline const char* to_string(AlternativeToInterestAmountEnum value) {
    switch (value) {
        case AlternativeToInterestAmountEnum::STANDARD: return "Standard";
        case AlternativeToInterestAmountEnum::ACTUAL_AMOUNT_RECEIVED: return "ActualAmountReceived";
        case AlternativeToInterestAmountEnum::TRANSFER_IF_DELIVERY_AMOUNT_BELOW_MTA: return "TransferIfDeliveryAmountBelowMTA";
        case AlternativeToInterestAmountEnum::OTHER: return "Other";
    }
    return "unknown";
}

/// Parse a string into AlternativeToInterestAmountEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AlternativeToInterestAmountEnum& out) {
    if (std::strcmp(str, "Standard") == 0) { out = AlternativeToInterestAmountEnum::STANDARD; return true; }
    if (std::strcmp(str, "ActualAmountReceived") == 0) { out = AlternativeToInterestAmountEnum::ACTUAL_AMOUNT_RECEIVED; return true; }
    if (std::strcmp(str, "TransferIfDeliveryAmountBelowMTA") == 0) { out = AlternativeToInterestAmountEnum::TRANSFER_IF_DELIVERY_AMOUNT_BELOW_MTA; return true; }
    if (std::strcmp(str, "Other") == 0) { out = AlternativeToInterestAmountEnum::OTHER; return true; }
    return false;
}

/// How is collateral interest to be handled?
enum class CollateralInterestHandlingEnum {
    ///  Transfer the interest each period 
    TRANSFER,
    ///  Adjust the collateral balance to include the interest amount 
    ADJUST,
    ///  Transfer the interest if it meets certain criteria, or otherwise adjust the collateral balance to reflect the interest amount  
    TRANSFER_OR_ADJUST
};

/// Convert CollateralInterestHandlingEnum to its string representation.
inline const char* to_string(CollateralInterestHandlingEnum value) {
    switch (value) {
        case CollateralInterestHandlingEnum::TRANSFER: return "Transfer";
        case CollateralInterestHandlingEnum::ADJUST: return "Adjust";
        case CollateralInterestHandlingEnum::TRANSFER_OR_ADJUST: return "Transfer_or_Adjust";
    }
    return "unknown";
}

/// Parse a string into CollateralInterestHandlingEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CollateralInterestHandlingEnum& out) {
    if (std::strcmp(str, "Transfer") == 0) { out = CollateralInterestHandlingEnum::TRANSFER; return true; }
    if (std::strcmp(str, "Adjust") == 0) { out = CollateralInterestHandlingEnum::ADJUST; return true; }
    if (std::strcmp(str, "Transfer_or_Adjust") == 0) { out = CollateralInterestHandlingEnum::TRANSFER_OR_ADJUST; return true; }
    return false;
}

/// The enumerated values to specify the application of Interest Amount with respect to the Delivery Amount through standard language.
enum class DeliveryAmountElectionEnum {
    /// The delivery only includes `Transfer on last Local Business Day.
    LAST_LOCAL_BUSINESS_DAY,
    /// The delivery includes both `Transfer on last Local Business Day` and `Transfer a Delivery Amount (IM) consisting of cash on any Local Business Day.`
    LAST_AND_ANY_LOCAL_BUSINESS_DAY
};

/// Convert DeliveryAmountElectionEnum to its string representation.
inline const char* to_string(DeliveryAmountElectionEnum value) {
    switch (value) {
        case DeliveryAmountElectionEnum::LAST_LOCAL_BUSINESS_DAY: return "LastLocalBusinessDay";
        case DeliveryAmountElectionEnum::LAST_AND_ANY_LOCAL_BUSINESS_DAY: return "LastAndAnyLocalBusinessDay";
    }
    return "unknown";
}

/// Parse a string into DeliveryAmountElectionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, DeliveryAmountElectionEnum& out) {
    if (std::strcmp(str, "LastLocalBusinessDay") == 0) { out = DeliveryAmountElectionEnum::LAST_LOCAL_BUSINESS_DAY; return true; }
    if (std::strcmp(str, "LastAndAnyLocalBusinessDay") == 0) { out = DeliveryAmountElectionEnum::LAST_AND_ANY_LOCAL_BUSINESS_DAY; return true; }
    return false;
}

/// The enumerated values to specify the type of margin for which a legal agreement is named.
enum class CollateralMarginTypeEnum {
    /// Denotes a margin agreement that is identified for use with Variation Margin/VM.
    VARIATION_MARGIN,
    /// Denotes a margin agreement that is identified for use with Initial Margin/IM.
    INITIAL_MARGIN
};

/// Convert CollateralMarginTypeEnum to its string representation.
inline const char* to_string(CollateralMarginTypeEnum value) {
    switch (value) {
        case CollateralMarginTypeEnum::VARIATION_MARGIN: return "VariationMargin";
        case CollateralMarginTypeEnum::INITIAL_MARGIN: return "InitialMargin";
    }
    return "unknown";
}

/// Parse a string into CollateralMarginTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CollateralMarginTypeEnum& out) {
    if (std::strcmp(str, "VariationMargin") == 0) { out = CollateralMarginTypeEnum::VARIATION_MARGIN; return true; }
    if (std::strcmp(str, "InitialMargin") == 0) { out = CollateralMarginTypeEnum::INITIAL_MARGIN; return true; }
    return false;
}

/// Represents an enumeration list to identify which Collateral Criteria type should have priority over others. If set to 'Issuer', the rating in the  Issuer Criteria has priority or is used if there is no Asset criteria. If set to 'Asset', the rating in the Asset Criteria has priority or is used if there is no Issuer rating.
enum class RatingPriorityResolutionEnum {
    /// Denotes that the Issuer Criteria has priority.
    ISSUER,
    /// Denotes that the Asset Criteria has priority.
    ASSET,
    /// Denotes that lowest rating should be used if several criteria apply.
    LOWEST,
    /// Denotes that highest rating should be used if several criteria apply.
    HIGHEST,
    /// Denotes that average rating should be used if several criteria apply.
    AVERAGE
};

/// Convert RatingPriorityResolutionEnum to its string representation.
inline const char* to_string(RatingPriorityResolutionEnum value) {
    switch (value) {
        case RatingPriorityResolutionEnum::ISSUER: return "Issuer";
        case RatingPriorityResolutionEnum::ASSET: return "Asset";
        case RatingPriorityResolutionEnum::LOWEST: return "Lowest";
        case RatingPriorityResolutionEnum::HIGHEST: return "Highest";
        case RatingPriorityResolutionEnum::AVERAGE: return "Average";
    }
    return "unknown";
}

/// Parse a string into RatingPriorityResolutionEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, RatingPriorityResolutionEnum& out) {
    if (std::strcmp(str, "Issuer") == 0) { out = RatingPriorityResolutionEnum::ISSUER; return true; }
    if (std::strcmp(str, "Asset") == 0) { out = RatingPriorityResolutionEnum::ASSET; return true; }
    if (std::strcmp(str, "Lowest") == 0) { out = RatingPriorityResolutionEnum::LOWEST; return true; }
    if (std::strcmp(str, "Highest") == 0) { out = RatingPriorityResolutionEnum::HIGHEST; return true; }
    if (std::strcmp(str, "Average") == 0) { out = RatingPriorityResolutionEnum::AVERAGE; return true; }
    return false;
}

