/// The enumerated values to specify the conditions that govern the adjustment to the number of units of the return swap.
enum class NotionalAdjustmentEnum {
    /// The adjustments to the number of units are governed by an execution clause.
    EXECUTION,
    /// The adjustments to the number of units are governed by a portfolio rebalancing clause.
    PORTFOLIO_REBALANCING,
    /// The adjustments to the number of units are not governed by any specific clause.
    STANDARD
};

/// Convert NotionalAdjustmentEnum to its string representation.
inline const char* to_string(NotionalAdjustmentEnum value) {
    switch (value) {
        case NotionalAdjustmentEnum::EXECUTION: return "Execution";
        case NotionalAdjustmentEnum::PORTFOLIO_REBALANCING: return "PortfolioRebalancing";
        case NotionalAdjustmentEnum::STANDARD: return "Standard";
    }
    return "unknown";
}

/// Parse a string into NotionalAdjustmentEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, NotionalAdjustmentEnum& out) {
    if (std::strcmp(str, "Execution") == 0) { out = NotionalAdjustmentEnum::EXECUTION; return true; }
    if (std::strcmp(str, "PortfolioRebalancing") == 0) { out = NotionalAdjustmentEnum::PORTFOLIO_REBALANCING; return true; }
    if (std::strcmp(str, "Standard") == 0) { out = NotionalAdjustmentEnum::STANDARD; return true; }
    return false;
}

/// Specifies delivery methods for securities transactions. This coding-scheme defines the possible delivery methods for securities.
enum class DeliveryMethodEnum {
    /// Indicates that a securities delivery must be made against payment in simultaneous transmissions and stipulate each other.
    DELIVERY_VERSUS_PAYMENT,
    /// Indicates that a securities delivery can be made without a simultaneous cash payment in exchange and not depending on if payment obligations are fulfilled or not and vice versa.
    FREE_OF_PAYMENT,
    /// Indicates that a securities delivery must be made in full before the payment for the securities; fulfillment of payment obligations depends on securities delivery obligations fulfillment.
    PRE_DELIVERY,
    /// Indicates that a payment in full amount must be made before the securities delivery; fulfillment of securities delivery obligations depends on payment obligations fulfillment.
    PRE_PAYMENT
};

/// Convert DeliveryMethodEnum to its string representation.
inline const char* to_string(DeliveryMethodEnum value) {
    switch (value) {
        case DeliveryMethodEnum::DELIVERY_VERSUS_PAYMENT: return "DeliveryVersusPayment";
        case DeliveryMethodEnum::FREE_OF_PAYMENT: return "FreeOfPayment";
        case DeliveryMethodEnum::PRE_DELIVERY: return "PreDelivery";
        case DeliveryMethodEnum::PRE_PAYMENT: return "PrePayment";
    }
    return "unknown";
}

/// Parse a string into DeliveryMethodEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, DeliveryMethodEnum& out) {
    if (std::strcmp(str, "DeliveryVersusPayment") == 0) { out = DeliveryMethodEnum::DELIVERY_VERSUS_PAYMENT; return true; }
    if (std::strcmp(str, "FreeOfPayment") == 0) { out = DeliveryMethodEnum::FREE_OF_PAYMENT; return true; }
    if (std::strcmp(str, "PreDelivery") == 0) { out = DeliveryMethodEnum::PRE_DELIVERY; return true; }
    if (std::strcmp(str, "PrePayment") == 0) { out = DeliveryMethodEnum::PRE_PAYMENT; return true; }
    return false;
}

/// The qualification of the type of transfers and cash flows associated with contracts and their lifecycle events.
enum class ScheduledTransferEnum {
    /// A cash flow corresponding to a corporate action event.
    CORPORATE_ACTION,
    /// A cash flow corresponding to the periodic accrued interests.
    COUPON,
    /// A cashflow resulting from a credit event.
    CREDIT_EVENT,
    /// A cash flow corresponding to the synthetic dividend of an equity underlier asset traded through a derivative instrument.
    DIVIDEND_RETURN,
    /// A cash flow associated with an exercise lifecycle event.
    EXERCISE,
    /// A cash flow corresponding to the return of the fixed interest rate portion of a derivative instrument that has different types of underlying assets, such as a total return swap.
    FIXED_RATE_RETURN,
    /// A cash flow corresponding to the return of the floating interest rate portion of a derivative instrument that has different types of underlying assets, such as a total return swap.
    FLOATING_RATE_RETURN,
    /// A cash flow corresponding to the compensation for missing assets due to the rounding of digits in the original number of assets to be delivered as per payout calculation.
    FRACTIONAL_AMOUNT,
    /// A cash flow corresponding to the return of the interest rate portion of a derivative instrument that has different types of underlying assets, such as a total return swap.
    INTEREST_RETURN,
    /// Net interest across payout components. Applicable to products such as interest rate swaps.
    NET_INTEREST,
    /// A cash flow corresponding to a performance return.  The settlementOrigin attribute on the Transfer should point to the relevant Payout defining the performance calculation.
    PERFORMANCE,
    /// An amount which corresponds to the notional of the contract for various business reasons. This could be associated to a cashflow (e.g. a principal payment) or a transfer (e.g. delivery of an asset).
    PRINCIPAL
};

/// Convert ScheduledTransferEnum to its string representation.
inline const char* to_string(ScheduledTransferEnum value) {
    switch (value) {
        case ScheduledTransferEnum::CORPORATE_ACTION: return "CorporateAction";
        case ScheduledTransferEnum::COUPON: return "Coupon";
        case ScheduledTransferEnum::CREDIT_EVENT: return "CreditEvent";
        case ScheduledTransferEnum::DIVIDEND_RETURN: return "DividendReturn";
        case ScheduledTransferEnum::EXERCISE: return "Exercise";
        case ScheduledTransferEnum::FIXED_RATE_RETURN: return "FixedRateReturn";
        case ScheduledTransferEnum::FLOATING_RATE_RETURN: return "FloatingRateReturn";
        case ScheduledTransferEnum::FRACTIONAL_AMOUNT: return "FractionalAmount";
        case ScheduledTransferEnum::INTEREST_RETURN: return "InterestReturn";
        case ScheduledTransferEnum::NET_INTEREST: return "NetInterest";
        case ScheduledTransferEnum::PERFORMANCE: return "Performance";
        case ScheduledTransferEnum::PRINCIPAL: return "Principal";
    }
    return "unknown";
}

/// Parse a string into ScheduledTransferEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, ScheduledTransferEnum& out) {
    if (std::strcmp(str, "CorporateAction") == 0) { out = ScheduledTransferEnum::CORPORATE_ACTION; return true; }
    if (std::strcmp(str, "Coupon") == 0) { out = ScheduledTransferEnum::COUPON; return true; }
    if (std::strcmp(str, "CreditEvent") == 0) { out = ScheduledTransferEnum::CREDIT_EVENT; return true; }
    if (std::strcmp(str, "DividendReturn") == 0) { out = ScheduledTransferEnum::DIVIDEND_RETURN; return true; }
    if (std::strcmp(str, "Exercise") == 0) { out = ScheduledTransferEnum::EXERCISE; return true; }
    if (std::strcmp(str, "FixedRateReturn") == 0) { out = ScheduledTransferEnum::FIXED_RATE_RETURN; return true; }
    if (std::strcmp(str, "FloatingRateReturn") == 0) { out = ScheduledTransferEnum::FLOATING_RATE_RETURN; return true; }
    if (std::strcmp(str, "FractionalAmount") == 0) { out = ScheduledTransferEnum::FRACTIONAL_AMOUNT; return true; }
    if (std::strcmp(str, "InterestReturn") == 0) { out = ScheduledTransferEnum::INTEREST_RETURN; return true; }
    if (std::strcmp(str, "NetInterest") == 0) { out = ScheduledTransferEnum::NET_INTEREST; return true; }
    if (std::strcmp(str, "Performance") == 0) { out = ScheduledTransferEnum::PERFORMANCE; return true; }
    if (std::strcmp(str, "Principal") == 0) { out = ScheduledTransferEnum::PRINCIPAL; return true; }
    return false;
}

/// The qualification of the type of ad-hoc transfers and cash flows that can be associated with contracts and their lifecycle events.
enum class UnscheduledTransferEnum {
    /// A recall of securities by the lender who has lent them out.
    RECALL,
    /// A return by the borrower to the lender of the full or partial quantity of securities on the contract.
    RETURN,
    /// A transfer resulting from the assignment of a contract to a new counterparty.
    ASSIGNMENT,
    /// The brokerage commission.
    BROKERAGE_COMMISSION,
    /// A transfer associated with an increase lifecycle event.
    INCREASE,
    /// The novation fee.
    NOVATION,
    /// A transfer associated with a partial termination lifecycle event.
    PARTIAL_TERMINATION,
    /// Denotes the amount payable by the buyer to the seller for an option. The premium is paid on the specified premium payment date or on each premium payment date if specified.
    PREMIUM,
    /// A transfer associated with a renegotiation lifecycle event.
    RENEGOTIATION,
    /// A transfer associated with a termination lifecycle event.
    TERMINATION,
    /// An upfront transfer associated to the swap to adjust for a difference between the swap price and the current market price.
    UPFRONT,
    /// A transfer associated with a credit event.
    CREDIT_EVENT,
    /// A transfer associated with a corporate action
    CORPORATE_ACTION
};

/// Convert UnscheduledTransferEnum to its string representation.
inline const char* to_string(UnscheduledTransferEnum value) {
    switch (value) {
        case UnscheduledTransferEnum::RECALL: return "Recall";
        case UnscheduledTransferEnum::RETURN: return "Return";
        case UnscheduledTransferEnum::ASSIGNMENT: return "Assignment";
        case UnscheduledTransferEnum::BROKERAGE_COMMISSION: return "BrokerageCommission";
        case UnscheduledTransferEnum::INCREASE: return "Increase";
        case UnscheduledTransferEnum::NOVATION: return "Novation";
        case UnscheduledTransferEnum::PARTIAL_TERMINATION: return "PartialTermination";
        case UnscheduledTransferEnum::PREMIUM: return "Premium";
        case UnscheduledTransferEnum::RENEGOTIATION: return "Renegotiation";
        case UnscheduledTransferEnum::TERMINATION: return "Termination";
        case UnscheduledTransferEnum::UPFRONT: return "Upfront";
        case UnscheduledTransferEnum::CREDIT_EVENT: return "CreditEvent";
        case UnscheduledTransferEnum::CORPORATE_ACTION: return "CorporateAction";
    }
    return "unknown";
}

/// Parse a string into UnscheduledTransferEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, UnscheduledTransferEnum& out) {
    if (std::strcmp(str, "Recall") == 0) { out = UnscheduledTransferEnum::RECALL; return true; }
    if (std::strcmp(str, "Return") == 0) { out = UnscheduledTransferEnum::RETURN; return true; }
    if (std::strcmp(str, "Assignment") == 0) { out = UnscheduledTransferEnum::ASSIGNMENT; return true; }
    if (std::strcmp(str, "BrokerageCommission") == 0) { out = UnscheduledTransferEnum::BROKERAGE_COMMISSION; return true; }
    if (std::strcmp(str, "Increase") == 0) { out = UnscheduledTransferEnum::INCREASE; return true; }
    if (std::strcmp(str, "Novation") == 0) { out = UnscheduledTransferEnum::NOVATION; return true; }
    if (std::strcmp(str, "PartialTermination") == 0) { out = UnscheduledTransferEnum::PARTIAL_TERMINATION; return true; }
    if (std::strcmp(str, "Premium") == 0) { out = UnscheduledTransferEnum::PREMIUM; return true; }
    if (std::strcmp(str, "Renegotiation") == 0) { out = UnscheduledTransferEnum::RENEGOTIATION; return true; }
    if (std::strcmp(str, "Termination") == 0) { out = UnscheduledTransferEnum::TERMINATION; return true; }
    if (std::strcmp(str, "Upfront") == 0) { out = UnscheduledTransferEnum::UPFRONT; return true; }
    if (std::strcmp(str, "CreditEvent") == 0) { out = UnscheduledTransferEnum::CREDIT_EVENT; return true; }
    if (std::strcmp(str, "CorporateAction") == 0) { out = UnscheduledTransferEnum::CORPORATE_ACTION; return true; }
    return false;
}

/// The enumeration values to specify how the option is to be settled when exercised.
enum class SettlementTypeEnum {
    /// The intrinsic value of the option will be delivered by way of a cash settlement amount determined, (i) by reference to the differential between the strike price and the settlement price; or (ii) in accordance with a bilateral agreement between the parties.
    CASH,
    /// The securities underlying the transaction will be delivered by (i) in the case of a call, the seller to the buyer, or (ii) in the case of a put, the buyer to the seller versus a settlement amount equivalent to the strike price per share.
    PHYSICAL,
    /// Allow Election of either Cash or Physical settlement.
    ELECTION,
    /// Allow use of either Cash or Physical settlement without prior Election.
    CASH_OR_PHYSICAL
};

/// Convert SettlementTypeEnum to its string representation.
inline const char* to_string(SettlementTypeEnum value) {
    switch (value) {
        case SettlementTypeEnum::CASH: return "Cash";
        case SettlementTypeEnum::PHYSICAL: return "Physical";
        case SettlementTypeEnum::ELECTION: return "Election";
        case SettlementTypeEnum::CASH_OR_PHYSICAL: return "CashOrPhysical";
    }
    return "unknown";
}

/// Parse a string into SettlementTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, SettlementTypeEnum& out) {
    if (std::strcmp(str, "Cash") == 0) { out = SettlementTypeEnum::CASH; return true; }
    if (std::strcmp(str, "Physical") == 0) { out = SettlementTypeEnum::PHYSICAL; return true; }
    if (std::strcmp(str, "Election") == 0) { out = SettlementTypeEnum::ELECTION; return true; }
    if (std::strcmp(str, "CashOrPhysical") == 0) { out = SettlementTypeEnum::CASH_OR_PHYSICAL; return true; }
    return false;
}

/// The enumeration values to specify how the transfer will settle, e.g. DvP.
enum class TransferSettlementEnum {
    /// Simultaneous transfer of two assets, typically securities, as a way to avoid settlement risk.
    DELIVERY_VERSUS_DELIVERY,
    /// Settlement in which the transfer of the asset and the cash settlement are simultaneous.
    DELIVERY_VERSUS_PAYMENT,
    /// Simultaneous transfer of cashflows.
    PAYMENT_VERSUS_PAYMENT,
    /// No central settlement.
    NOT_CENTRAL_SETTLEMENT
};

/// Convert TransferSettlementEnum to its string representation.
inline const char* to_string(TransferSettlementEnum value) {
    switch (value) {
        case TransferSettlementEnum::DELIVERY_VERSUS_DELIVERY: return "DeliveryVersusDelivery";
        case TransferSettlementEnum::DELIVERY_VERSUS_PAYMENT: return "DeliveryVersusPayment";
        case TransferSettlementEnum::PAYMENT_VERSUS_PAYMENT: return "PaymentVersusPayment";
        case TransferSettlementEnum::NOT_CENTRAL_SETTLEMENT: return "NotCentralSettlement";
    }
    return "unknown";
}

/// Parse a string into TransferSettlementEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, TransferSettlementEnum& out) {
    if (std::strcmp(str, "DeliveryVersusDelivery") == 0) { out = TransferSettlementEnum::DELIVERY_VERSUS_DELIVERY; return true; }
    if (std::strcmp(str, "DeliveryVersusPayment") == 0) { out = TransferSettlementEnum::DELIVERY_VERSUS_PAYMENT; return true; }
    if (std::strcmp(str, "PaymentVersusPayment") == 0) { out = TransferSettlementEnum::PAYMENT_VERSUS_PAYMENT; return true; }
    if (std::strcmp(str, "NotCentralSettlement") == 0) { out = TransferSettlementEnum::NOT_CENTRAL_SETTLEMENT; return true; }
    return false;
}

/// The enumerated values to specify whether a trade is settling using standard settlement instructions as well as whether it is a candidate for settlement netting.
enum class StandardSettlementStyleEnum {
    /// This trade will settle using standard predetermined funds settlement instructions.
    STANDARD,
    /// This trade is a candidate for settlement netting.
    NET,
    /// This trade will settle using standard predetermined funds settlement instructions and is a candidate for settlement netting.
    STANDARD_AND_NET,
    /// These trades have been paired and are a candidate for settlement netting.
    PAIR_AND_NET
};

/// Convert StandardSettlementStyleEnum to its string representation.
inline const char* to_string(StandardSettlementStyleEnum value) {
    switch (value) {
        case StandardSettlementStyleEnum::STANDARD: return "Standard";
        case StandardSettlementStyleEnum::NET: return "Net";
        case StandardSettlementStyleEnum::STANDARD_AND_NET: return "StandardAndNet";
        case StandardSettlementStyleEnum::PAIR_AND_NET: return "PairAndNet";
    }
    return "unknown";
}

/// Parse a string into StandardSettlementStyleEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, StandardSettlementStyleEnum& out) {
    if (std::strcmp(str, "Standard") == 0) { out = StandardSettlementStyleEnum::STANDARD; return true; }
    if (std::strcmp(str, "Net") == 0) { out = StandardSettlementStyleEnum::NET; return true; }
    if (std::strcmp(str, "StandardAndNet") == 0) { out = StandardSettlementStyleEnum::STANDARD_AND_NET; return true; }
    if (std::strcmp(str, "PairAndNet") == 0) { out = StandardSettlementStyleEnum::PAIR_AND_NET; return true; }
    return false;
}

/// Defines the different cash settlement methods for a product where cash settlement is applicable.
enum class CashSettlementMethodEnum {
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (a).
    CASH_PRICE_METHOD,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (b).
    CASH_PRICE_ALTERNATE_METHOD,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (c).
    PAR_YIELD_CURVE_ADJUSTED_METHOD,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (d).
    ZERO_COUPON_YIELD_ADJUSTED_METHOD,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (e).
    PAR_YIELD_CURVE_UNADJUSTED_METHOD,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (f) (published in Supplement number 23).
    CROSS_CURRENCY_METHOD,
    /// An ISDA defined cash settlement method (yield curve) used for the determination of the applicable cash settlement amount. The method is defined in the 2006 ISDA Definitions, Section 18.3. Cash Settlement Methods, paragraph (g) (published in Supplement number 28). The method is defined in the 2021 ISDA Definitions, section 18.2.6.
    COLLATERALIZED_CASH_PRICE_METHOD,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2021 ISDA Definitions, Section 18.2.1.
    MID_MARKET_INDICATIVE_QUOTATIONS,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2021 ISDA Definitions, Section 18.2.2.
    MID_MARKET_INDICATIVE_QUOTATIONS_ALTERNATE,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2021 ISDA Definitions, Section 18.2.3.
    MID_MARKET_CALCULATION_AGENT_DETERMINATION,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2021 ISDA Definitions, Section 18.2.4.
    REPLACEMENT_VALUE_FIRM_QUOTATIONS,
    /// An ISDA defined cash settlement method used for the determination of the applicable cash settlement amount. The method is defined in the 2021 ISDA Definitions, Section 18.2.5
    REPLACEMENT_VALUE_CALCULATION_AGENT_DETERMINATION
};

/// Convert CashSettlementMethodEnum to its string representation.
inline const char* to_string(CashSettlementMethodEnum value) {
    switch (value) {
        case CashSettlementMethodEnum::CASH_PRICE_METHOD: return "CashPriceMethod";
        case CashSettlementMethodEnum::CASH_PRICE_ALTERNATE_METHOD: return "CashPriceAlternateMethod";
        case CashSettlementMethodEnum::PAR_YIELD_CURVE_ADJUSTED_METHOD: return "ParYieldCurveAdjustedMethod";
        case CashSettlementMethodEnum::ZERO_COUPON_YIELD_ADJUSTED_METHOD: return "ZeroCouponYieldAdjustedMethod";
        case CashSettlementMethodEnum::PAR_YIELD_CURVE_UNADJUSTED_METHOD: return "ParYieldCurveUnadjustedMethod";
        case CashSettlementMethodEnum::CROSS_CURRENCY_METHOD: return "CrossCurrencyMethod";
        case CashSettlementMethodEnum::COLLATERALIZED_CASH_PRICE_METHOD: return "CollateralizedCashPriceMethod";
        case CashSettlementMethodEnum::MID_MARKET_INDICATIVE_QUOTATIONS: return "MidMarketIndicativeQuotations";
        case CashSettlementMethodEnum::MID_MARKET_INDICATIVE_QUOTATIONS_ALTERNATE: return "MidMarketIndicativeQuotationsAlternate";
        case CashSettlementMethodEnum::MID_MARKET_CALCULATION_AGENT_DETERMINATION: return "MidMarketCalculationAgentDetermination";
        case CashSettlementMethodEnum::REPLACEMENT_VALUE_FIRM_QUOTATIONS: return "ReplacementValueFirmQuotations";
        case CashSettlementMethodEnum::REPLACEMENT_VALUE_CALCULATION_AGENT_DETERMINATION: return "ReplacementValueCalculationAgentDetermination";
    }
    return "unknown";
}

/// Parse a string into CashSettlementMethodEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, CashSettlementMethodEnum& out) {
    if (std::strcmp(str, "CashPriceMethod") == 0) { out = CashSettlementMethodEnum::CASH_PRICE_METHOD; return true; }
    if (std::strcmp(str, "CashPriceAlternateMethod") == 0) { out = CashSettlementMethodEnum::CASH_PRICE_ALTERNATE_METHOD; return true; }
    if (std::strcmp(str, "ParYieldCurveAdjustedMethod") == 0) { out = CashSettlementMethodEnum::PAR_YIELD_CURVE_ADJUSTED_METHOD; return true; }
    if (std::strcmp(str, "ZeroCouponYieldAdjustedMethod") == 0) { out = CashSettlementMethodEnum::ZERO_COUPON_YIELD_ADJUSTED_METHOD; return true; }
    if (std::strcmp(str, "ParYieldCurveUnadjustedMethod") == 0) { out = CashSettlementMethodEnum::PAR_YIELD_CURVE_UNADJUSTED_METHOD; return true; }
    if (std::strcmp(str, "CrossCurrencyMethod") == 0) { out = CashSettlementMethodEnum::CROSS_CURRENCY_METHOD; return true; }
    if (std::strcmp(str, "CollateralizedCashPriceMethod") == 0) { out = CashSettlementMethodEnum::COLLATERALIZED_CASH_PRICE_METHOD; return true; }
    if (std::strcmp(str, "MidMarketIndicativeQuotations") == 0) { out = CashSettlementMethodEnum::MID_MARKET_INDICATIVE_QUOTATIONS; return true; }
    if (std::strcmp(str, "MidMarketIndicativeQuotationsAlternate") == 0) { out = CashSettlementMethodEnum::MID_MARKET_INDICATIVE_QUOTATIONS_ALTERNATE; return true; }
    if (std::strcmp(str, "MidMarketCalculationAgentDetermination") == 0) { out = CashSettlementMethodEnum::MID_MARKET_CALCULATION_AGENT_DETERMINATION; return true; }
    if (std::strcmp(str, "ReplacementValueFirmQuotations") == 0) { out = CashSettlementMethodEnum::REPLACEMENT_VALUE_FIRM_QUOTATIONS; return true; }
    if (std::strcmp(str, "ReplacementValueCalculationAgentDetermination") == 0) { out = CashSettlementMethodEnum::REPLACEMENT_VALUE_CALCULATION_AGENT_DETERMINATION; return true; }
    return false;
}

