/// The enumerated values to specify the type of averaging used in an Asian option.
enum class AveragingInOutEnum {
    /// The average price is used to derive the strike price. Also known as 'Asian strike' style option.
    IN,
    /// The average price is used to derive the expiration price. Also known as 'Asian price' style option.
    OUT,
    /// The average price is used to derive both the strike and the expiration price.
    BOTH
};

/// Convert AveragingInOutEnum to its string representation.
inline const char* to_string(AveragingInOutEnum value) {
    switch (value) {
        case AveragingInOutEnum::IN: return "In";
        case AveragingInOutEnum::OUT: return "Out";
        case AveragingInOutEnum::BOTH: return "Both";
    }
    return "unknown";
}

/// Parse a string into AveragingInOutEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, AveragingInOutEnum& out) {
    if (std::strcmp(str, "In") == 0) { out = AveragingInOutEnum::IN; return true; }
    if (std::strcmp(str, "Out") == 0) { out = AveragingInOutEnum::OUT; return true; }
    if (std::strcmp(str, "Both") == 0) { out = AveragingInOutEnum::BOTH; return true; }
    return false;
}

/// The enumerated values to specify the type or strategy of the option.
enum class OptionTypeEnum {
    /// A 'payer' option: If you buy a 'payer' option you have the right but not the obligation to enter into the underlying swap transaction as the 'fixed' rate/price payer and receive float.
    PAYER,
    /// A 'receiver' option: If you buy a 'receiver' option you have the right but not the obligation to enter into the underlying swap transaction as the 'fixed' rate/price receiver and pay float.
    RECEIVER,
    /// A straddle strategy, which involves the simultaneous buying of a put and a call of the same underlier, at the same strike and same expiration date
    STRADDLE
};

/// Convert OptionTypeEnum to its string representation.
inline const char* to_string(OptionTypeEnum value) {
    switch (value) {
        case OptionTypeEnum::PAYER: return "Payer";
        case OptionTypeEnum::RECEIVER: return "Receiver";
        case OptionTypeEnum::STRADDLE: return "Straddle";
    }
    return "unknown";
}

/// Parse a string into OptionTypeEnum. Returns false if the string is not a valid value.
inline bool from_string(const char* str, OptionTypeEnum& out) {
    if (std::strcmp(str, "Payer") == 0) { out = OptionTypeEnum::PAYER; return true; }
    if (std::strcmp(str, "Receiver") == 0) { out = OptionTypeEnum::RECEIVER; return true; }
    if (std::strcmp(str, "Straddle") == 0) { out = OptionTypeEnum::STRADDLE; return true; }
    return false;
}

